func:
let opts;
try {
  opts = JSON.parse(msg.payload);
} catch (e) {
  node.error("options.json invalide: " + e.toString(), msg);
  node.status({ fill: "red", shape: "ring", text: "options.json invalide" });
  return null;
}

/* =========================
   TIMEZONE
   ========================= */
let tz = "UTC";
const tzMode = (opts.timezone_mode || "UTC").toString().trim();
const tzCustom = (opts.timezone_custom || "UTC").toString().trim();
tz = (tzMode === "CUSTOM") ? (tzCustom || "UTC") : tzMode;

try {
  new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
} catch (e) {
  tz = "UTC";
}

global.set("addon_timezone", tz);
node.warn("Timezone loaded: " + tz);

/* =========================
   BATTERY SYSTEM VOLTAGE
   ========================= */
let batterySystemVoltageRaw = (opts.battery_system_voltage ?? "48V")
  .toString()
  .toUpperCase()
  .replace(/\s+/g, "")
  .replace("V", "")
  .trim();

let batterySystemVoltage = Number(batterySystemVoltageRaw);
if (batterySystemVoltage !== 24 && batterySystemVoltage !== 48) {
  batterySystemVoltage = 48;
}

global.set("battery_system_voltage", batterySystemVoltage);
global.set("config.batterySystemVoltage", batterySystemVoltage);
node.warn("Battery system voltage loaded: " + batterySystemVoltage + "V");

/* =========================
   HELPERS
   ========================= */
function normStr(v) {
  return (v ?? "").toString().trim();
}

function isValidSerial(p) {
  p = normStr(p);
  if (!p) return false;
  if (p.includes("CHANGE-ME")) return false;
  return p.startsWith("/dev/serial/") || p.startsWith("/dev/tty");
}

function isValidHost(h) {
  h = normStr(h);
  if (!h) return false;
  if (h.includes("CHANGE-ME")) return false;
  return true;
}

function isValidPort(p) {
  const n = Number(p);
  return Number.isInteger(n) && n >= 1 && n <= 65535;
}

function sanitizeTransport(v) {
  v = normStr(v).toLowerCase();
  return (v === "gateway" || v === "tcp") ? "tcp" : "serial";
}

/* =========================
   READ PER-INVERTER CONFIG
   UI/add-on keys:
   - inv1_link
   - inv1_serial_port
   - inv1_gateway_host
   - inv1_gateway_port
   ========================= */
const invCfg = {};

for (let i = 1; i <= 3; i++) {
  const link = normStr(opts[`inv${i}_link`] || "serial").toLowerCase();
  const transport = sanitizeTransport(link);

  const serialPort = normStr(opts[`inv${i}_serial_port`] || "");
  const gwHost = normStr(opts[`inv${i}_gateway_host`] || "");
  const gwPortRaw = opts[`inv${i}_gateway_port`];
  const gwPort = isValidPort(gwPortRaw) ? Number(gwPortRaw) : 8899;

  invCfg[i] = {
    link,
    transport,
    serialPort,
    gwHost,
    gwPort
  };

  node.warn(
    `INV${i} link=${link} transport=${transport} serial=${serialPort || "-"} host=${gwHost || "-"} port=${gwPort}`
  );
}

/* =========================
   DETERMINE ACTIVE INVERTERS
   - serial: valid serial port required
   - tcp: valid host + valid port required
   ========================= */
const activeInvs = [];
const serialPortsByInv = {};

for (let i = 1; i <= 3; i++) {
  const c = invCfg[i];

  if (c.transport === "tcp") {
    if (isValidHost(c.gwHost) && isValidPort(c.gwPort)) {
      activeInvs.push(i);
    }
  } else {
    if (isValidSerial(c.serialPort)) {
      activeInvs.push(i);
      serialPortsByInv[i] = c.serialPort;
    }
  }
}

/* =========================
   COMPAT: list of valid serial ports only
   ========================= */
const serialPorts = Object.keys(serialPortsByInv)
  .sort((a, b) => Number(a) - Number(b))
  .map(k => serialPortsByInv[k]);

/* =========================
   MQTT CONFIG
   ========================= */
const mqttConfig = {
  baseTopic: opts.mqtt_prefix || "voltronic",
  discoveryPrefix: "homeassistant",
  deviceName: "Onduleur Voltronic",
  broker: opts.mqtt_host || "core-mosquitto",
  port: Number(opts.mqtt_port) || 1883,
  user: normStr(opts.mqtt_user),
  pass: normStr(opts.mqtt_pass)
};

/* =========================
   POLLING FAST
   ========================= */
const fastSecRaw = (opts.polling_fast ?? opts.polling?.fast ?? 5);
const fastSec = Number(fastSecRaw);
const pollingFastMs = (Number.isFinite(fastSec) && fastSec > 0 ? fastSec : 5) * 1000;

/* =========================
   WRITE GLOBAL CONFIG
   ========================= */
global.set("config.mqtt", mqttConfig);
global.set("config.pollingFastMs", pollingFastMs);
global.set("config.invCfg", invCfg);
global.set("config.invertersList", activeInvs);
global.set("config.invertersCount", activeInvs.length);
global.set("config.serialPorts", serialPorts);

/* =========================
   INIT inverter_1..3 slots
   ========================= */
for (let i = 1; i <= 3; i++) {
  global.set(`inverter_${i}.port`, serialPortsByInv[i] || null);

  if (!global.get(`inverter_${i}.data`)) {
    global.set(`inverter_${i}.data`, {});
  }

  global.set(`inverter_${i}.lastUpdate`, 0);
}

/* =========================
   DEBUG
   ========================= */
node.warn("PARSE OPTIONS DEBUG -> " + JSON.stringify({
  invCfg,
  activeInvs,
  serialPorts
}));

/* =========================
   STATUS + PAYLOAD
   ========================= */
node.status({
  fill: activeInvs.length ? "green" : "yellow",
  shape: activeInvs.length ? "dot" : "ring",
  text: `Config OK (${activeInvs.length} inverter(s) active)`
});

msg.payload = {
  inverters: activeInvs.length,
  invertersList: activeInvs,
  serialPorts,
  invCfg,
  mqtt: {
    broker: mqttConfig.broker,
    port: mqttConfig.port,
    baseTopic: mqttConfig.baseTopic
  },
  pollingFastMs,
  timezone: tz,
  batterySystemVoltage
};

return msg;

// INIT helpers - à lancer une fois au démarrage
if (!global.get("helpers")) global.set("helpers", {});

const helpers = global.get("helpers");

if (typeof helpers.buildVoltronicCommand !== "function") {
  function crc16_xmodem(buf) {
    let crc = 0x0000;
    for (const b of buf) {
      crc ^= (b << 8);
      for (let i = 0; i < 8; i++) {
        crc = (crc & 0x8000) ? ((crc << 1) ^ 0x1021) : (crc << 1);
        crc &= 0xFFFF;
      }
    }
    return crc & 0xFFFF;
  }

  helpers.buildVoltronicCommand = function (cmd) {
    cmd = (cmd || "").toString().trim();
    const data = Buffer.from(cmd, "ascii");
    const crc = crc16_xmodem(data);
    const frame = Buffer.alloc(data.length + 3);
    data.copy(frame, 0);
    frame.writeUInt16BE(crc, data.length);
    frame[frame.length - 1] = 0x0D; // \r
    return frame;
  };

  global.set("helpers", helpers);
}

node.status({ fill: "green", shape: "dot", text: "helpers OK" });
return null;

// ====== CONSTRUIRE COMMANDE (Voltronic) ======
const helpers = global.get("helpers");

if (!helpers || typeof helpers.buildVoltronicCommand !== "function") {
  node.error("helpers.buildVoltronicCommand introuvable (global.helpers)");
  return null;
}

// Récupère la commande (priorité à msg.command)
let cmd = (msg.command ?? msg._cmd ?? msg.payload ?? "")
  .toString()
  .trim();

// ------------------------------
// FIX: commandes qui arrivent avec guillemets
// ex: '"PBATMAXDISC150"' ou 'PBATMAXDISC150""'
// ------------------------------

// si c'est du JSON stringifié (ex: "\"PBATMAXDISC150\""), tente parse
try {
  if (cmd.startsWith('"') || cmd.startsWith('\\"')) {
    const parsed = JSON.parse(cmd);
    if (typeof parsed === "string") cmd = parsed;
  }
} catch (e) {
  // ignore
}

// retire guillemets parasites au début/fin
cmd = cmd.trim().replace(/^"+|"+$/g, "");

// upper après nettoyage
cmd = cmd.toUpperCase();

if (!cmd) {
  node.warn("Commande vide -> ignorée");
  return null;
}

/*
  Validation "safe" :
  - Requêtes classiques: QPIGS, QPIRI, QMOD, QET, QLD20260220, etc.
  - SET Voltronic: souvent Pxxxx + valeur (ex: PCVV55.7, PBT02, PBATMAXDISC150, etc.)
  On autorise uniquement: A-Z / 0-9 / '.' / '-' et on contrôle les patterns.
*/
const isQueryOrStat =
  /^[A-Z]{2,6}[0-9]*$/.test(cmd); // ex: QPIGS, QPIRI, QET, QED20260220, QEY2026...

const isSetWithValue =
  /^P[A-Z0-9]{2,12}-?[0-9]+(\.[0-9]+)?$/.test(cmd);
// ↑ élargi à 2..12 (PBATMAXDISC = 10 lettres après P)

// IMPORTANT: PBATMAXDISC est un SET spécial avec 3 digits, ex: PBATMAXDISC150
// Il match déjà la regex ci-dessus, mais on garde ce commentaire pour clarté.

if (!isQueryOrStat && !isSetWithValue) {
  node.warn(`Commande invalide ignorée: "${cmd}"`);
  return null;
}

// Conserver la commande envoyée (utile pour associer RX)
msg.command = cmd;
msg._cmd = cmd;

// Construire la trame (CRC + CR)
let buf;
try {
  buf = helpers.buildVoltronicCommand(cmd);
} catch (e) {
  node.error(`Erreur buildVoltronicCommand("${cmd}") : ${e.message || e}`);
  return null;
}

// Payload = Buffer à envoyer dans Serial Out
msg.payload = buf;

// Debug utile
msg._tx_ts = Date.now();
msg._tx_ascii = cmd;
msg._tx_hex = buf.toString("hex");

// Status (optionnel)
node.status({
  fill: "blue",
  shape: "dot",
  text: `${cmd} → ond${msg.inverterNum ?? "?"}`
});

// Mémorise la dernière commande par onduleur (utile RX/timeout)
if (msg.inverterNum != null) {
  flow.set(`inv${msg.inverterNum}_last_cmd`, msg._cmd);
  flow.set(`inv${msg.inverterNum}_last_cmd_ts`, Date.now());
}

return msg;

// ====== REQUETES (Option A + firstRun + force + QPIGS2 auto-disable + retry 1h + DIAG) ======
// ✅ Fix: QPIRI/QDOP + DIAG/FW bien envoyés AU BOOT
// ✅ Fix: Burst boot exécuté AVANT le tick realtime (évite “perte” si queue/pump limité)
// ✅ Garde ta logique QPIGS2 auto-disable + retry 1h

const inverterNum = 1;
const ts = Date.now();
const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());

const yyyymm = `${yyyy}${mm}`;
const yyyymmdd = `${yyyy}${mm}${dd}`;

// état alternance
let alt = context.get("alt");
if (alt === undefined || alt === null) alt = 0;

// firstRun peut rester false si context persistant
let firstRun = context.get("firstRun");
if (firstRun === undefined) firstRun = true;

// Permet de forcer un burst via un inject bouton (msg.forceFirstRun=true)
if (msg && msg.forceFirstRun === true) {
  firstRun = true;
}

// timers existants
let nextQMOD = context.get("nextQMOD");
let nextHour = context.get("nextHour");
let nextDay10m = context.get("nextDay10m");
let nextMonth6 = context.get("nextMonth6");
let nextYear24 = context.get("nextYear24");

// timers params
let nextQPIRI = context.get("nextQPIRI");
let nextQDOP = context.get("nextQDOP");

// retry QPIGS2 même si désactivé
let nextRetryQPIGS2 = context.get("nextRetryQPIGS2");
if (!nextRetryQPIGS2) nextRetryQPIGS2 = ts + 60 * 60 * 1000;

// ✅ DIAG timers
let diagDone = context.get("diagDone");           // 1-shot after boot (flag)
let nextQPIWS = context.get("nextQPIWS");         // 5 min

function makeCmd(cmd) {
  return { inverterNum, command: cmd, _cmd: cmd, payload: cmd };
}

const msgs = [];

// ----- QPIGS/QPIGS2 stratégie -----
const supportsQPIGS2 = flow.get(`inv${inverterNum}_supports_qpigs2`);
const useQPIGS2 = (supportsQPIGS2 !== false);

function pushRealtimeTick() {
  if (useQPIGS2) {
    msgs.push(makeCmd(alt === 0 ? "QPIGS" : "QPIGS2"));
    alt = alt ? 0 : 1;
  } else {
    msgs.push(makeCmd("QPIGS"));
    if (ts >= nextRetryQPIGS2) {
      msgs.push(makeCmd("QPIGS2"));
      nextRetryQPIGS2 = ts + 60 * 60 * 1000;
    }
  }
}

// =========================
// 1) BOOT BURST (firstRun)
// =========================
if (firstRun) {
  const burst = [
    // ✅ PARAMS AU BOOT (sinon tu attends 5 minutes)
    "QPIRI",
    "QDOP",

    // realtime info utile
    "QMOD",

    // energies
    "QET", `QEY${yyyy}`, `QEM${yyyymm}`, `QED${yyyymmdd}`,
    "QLT", `QLY${yyyy}`, `QLM${yyyymm}`, `QLD${yyyymmdd}`,

    // ✅ DIAG au boot
    "QMN",      // model
    "QID",      // serial (si besoin: remplacer par QSID)
    "QVFW",     // fw main
    "QVFW3",    // fw remote/panel (si supporté)
    "QPIWS"     // warnings/faults (1er état)
  ];

  burst.forEach(c => msgs.push(makeCmd(c)));

  // Schedules
  nextQMOD = ts + 5 * 60 * 1000;
  nextHour = ts + 60 * 60 * 1000;
  nextDay10m = ts + 10 * 60 * 1000;
  nextMonth6 = ts + 6 * 60 * 60 * 1000;
  nextYear24 = ts + 24 * 60 * 60 * 1000;

  // ✅ Tu viens de les envoyer -> replanifie à +5 minutes
  nextQPIRI = ts + 5 * 60 * 1000;
  nextQDOP = ts + 5 * 60 * 1000;

  // ✅ DIAG flags/timers
  diagDone = true;
  nextQPIWS = ts + 5 * 60 * 1000;

  firstRun = false;

  node.status({ fill: "green", shape: "dot", text: `FIRST RUN: ${msgs.length} cmds` });
}

// =========================
// 2) NORMAL MODE (timers)
// =========================
else {
  // QMOD 5 min
  if (nextQMOD == null) nextQMOD = ts + 5 * 60 * 1000;
  if (ts >= nextQMOD) {
    msgs.push(makeCmd("QMOD"));
    nextQMOD = ts + 5 * 60 * 1000;
  }

  // QPIRI 5 min
  if (nextQPIRI == null) nextQPIRI = ts + 5 * 60 * 1000;
  if (ts >= nextQPIRI) {
    msgs.push(makeCmd("QPIRI"));
    nextQPIRI = ts + 5 * 60 * 1000;
  }

  // QDOP 5 min
  if (nextQDOP == null) nextQDOP = ts + 5 * 60 * 1000;
  if (ts >= nextQDOP) {
    msgs.push(makeCmd("QDOP"));
    nextQDOP = ts + 5 * 60 * 1000;
  }

  // ✅ QPIWS (fault/warnings) 5 min
  if (nextQPIWS == null) nextQPIWS = ts + 5 * 60 * 1000;
  if (ts >= nextQPIWS) {
    msgs.push(makeCmd("QPIWS"));
    nextQPIWS = ts + 5 * 60 * 1000;
  }

  // Hourly
  if (nextHour == null) nextHour = ts + 60 * 60 * 1000;
  if (ts >= nextHour) {
    // énergies (total)
    msgs.push(makeCmd("QET"));
    msgs.push(makeCmd("QLT"));

    // diagnostics (1 fois/heure)
    msgs.push(makeCmd("QMN"));
    msgs.push(makeCmd("QID"));
    msgs.push(makeCmd("QVFW"));
    msgs.push(makeCmd("QVFW3"));

    nextHour = ts + 60 * 60 * 1000;
  }

  // Daily 10min
  if (nextDay10m == null) nextDay10m = ts + 10 * 60 * 1000;
  if (ts >= nextDay10m) {
    msgs.push(makeCmd(`QED${yyyymmdd}`));
    msgs.push(makeCmd(`QLD${yyyymmdd}`));
    nextDay10m = ts + 10 * 60 * 1000;
  }

  // Monthly 6h
  if (nextMonth6 == null) nextMonth6 = ts + 6 * 60 * 60 * 1000;
  if (ts >= nextMonth6) {
    msgs.push(makeCmd(`QEM${yyyymm}`));
    msgs.push(makeCmd(`QLM${yyyymm}`));
    nextMonth6 = ts + 6 * 60 * 60 * 1000;
  }

  // Yearly 24h
  if (nextYear24 == null) nextYear24 = ts + 24 * 60 * 60 * 1000;
  if (ts >= nextYear24) {
    msgs.push(makeCmd(`QEY${yyyy}`));
    msgs.push(makeCmd(`QLY${yyyy}`));
    nextYear24 = ts + 24 * 60 * 60 * 1000;
  }
}

// =========================
// 3) REALTIME TICK (toujours à la fin)
// =========================
pushRealtimeTick();

// =========================
// save context
// =========================
context.set("alt", alt);
context.set("firstRun", firstRun);
context.set("nextQMOD", nextQMOD);
context.set("nextHour", nextHour);
context.set("nextDay10m", nextDay10m);
context.set("nextMonth6", nextMonth6);
context.set("nextYear24", nextYear24);
context.set("nextQPIRI", nextQPIRI);
context.set("nextQDOP", nextQDOP);
context.set("nextRetryQPIGS2", nextRetryQPIGS2);

// ✅ save DIAG
context.set("diagDone", diagDone);
context.set("nextQPIWS", nextQPIWS);

return [msgs];

// ====== PARSER 1 (Voltronic) - QUEUE MODE ======
// Entrée: msg.payload = Buffer (Serial IN en "a single buffer", pas de split)
// Sorties:
//   1) trigger pump (msg.topic="pump")
//   2) data parsée (vers normalize state)
// Associe la réponse à la commande "inflight" (envoyée par Queue Pump)

const inv = msg.inverterNum ?? 1;
if (!Buffer.isBuffer(msg.payload)) return null;

// --- accumulateur RX ---
let rx = context.get("rxbuf");
if (!Buffer.isBuffer(rx)) rx = Buffer.alloc(0);

// sécurité overflow
if (rx.length > 8192) rx = Buffer.alloc(0);

// concat
rx = Buffer.concat([rx, msg.payload]);

const CR = 0x0D;

// extrait toutes les frames finissant par CR
const frames = [];
while (true) {
  const idx = rx.indexOf(CR);
  if (idx === -1) break;
  frames.push(rx.slice(0, idx + 1));
  rx = rx.slice(idx + 1);
}
context.set("rxbuf", rx);

if (!frames.length) return null;

// commande inflight (celle réellement envoyée)
const inflightKey = `inv${inv}_inflight`;
const inflight = flow.get(inflightKey);
const inflightCmd = inflight?.cmd || "UNKNOWN";

// Nettoyage trame -> ASCII sans CRC/CR
function cleanAsciiFromFrame(frameBuf) {
  // NAK brut possible (0x15)
  if (frameBuf.length === 1 && frameBuf[0] === 0x15) return "NAK";

  // Normalement: <data ASCII> + <CRC 2 bytes> + <CR>
  let dataBuf = frameBuf;

  if (frameBuf.length >= 3 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -3); // retire CRC(2) + CR(1)
  } else if (frameBuf.length >= 1 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -1); // fallback retire CR
  }

  return dataBuf.toString("ascii");
}

function parseFrame(frameBuf, cmd) {
  const ascii = cleanAsciiFromFrame(frameBuf);

  // Détection NAK "NAK" ou 0x15
  if (ascii.includes("NAK") || ascii === "NAK") {
    return {
      inverter: inv,
      command: cmd,
      nak: true,
      raw: "NAK",
      fields: [],
      nums: [],
      value: null
    };
  }

  // Enlever parenthèses si présentes
  let body = ascii.trim();
  if (body.startsWith("(")) body = body.slice(1);
  if (body.endsWith(")")) body = body.slice(0, -1);
  body = body.trim();

  const fields = body.length ? body.split(/\s+/) : [];
  const nums = fields.map(v => {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  });

  // Cas énergie (1 valeur)
  const isEnergyCmd = /^Q(E[TYMD]|L[TYMD])/.test(cmd);
  let value = null;
  if (isEnergyCmd && fields.length >= 1) {
    const n0 = Number(fields[0]);
    if (Number.isFinite(n0)) value = n0;
  }

  return {
    inverter: inv,
    command: cmd,
    raw: body,
    fields,
    nums,
    value
  };
}

// Ici, on part du principe QUEUE = 1 commande envoyée -> 1 réponse attendue.
// Mais on gère quand même le cas "plusieurs frames d'un coup" :
// - 1ère frame = inflightCmd
// - frames suivantes = UNKNOWN (ou on garde inflightCmd si tu préfères)
const outMsgs = [];
for (let i = 0; i < frames.length; i++) {
  const cmd = (i === 0) ? inflightCmd : "UNKNOWN";
  outMsgs.push({
    inverterNum: inv,
    _cmd: cmd,
    command: cmd,
    payload: parseFrame(frames[i], cmd),
    _rx_ts: Date.now()
  });
}

// ACK : dès qu'on reçoit au moins une frame, on libère inflight
flow.set(inflightKey, null);

// Trigger pump immédiatement (pour envoyer la prochaine commande)
const pumpMsg = { inverterNum: inv, topic: "pump" };

// Sortie 1: pump trigger
// Sortie 2: data parsée (plusieurs messages possibles)
return [[pumpMsg], outMsgs];

// ====== NORMALIZE STATE (AUTO / MULTI-MODEL) - + TZ dynamic + GRID TODAY ======
if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? msg.payload.inverter ?? 1;

// Normaliser la commande (évite "QPIRI\r", "qpiri", "QPIRI ")
const cmd = String(msg.payload.command || msg.command || msg._cmd || "UNKNOWN")
  .trim()
  .toUpperCase();

const f = Array.isArray(msg.payload.fields) ? msg.payload.fields : [];
const n = Array.isArray(msg.payload.nums) ? msg.payload.nums : [];
const value = msg.payload.value;

let state = context.get("state");
if (!state || typeof state !== "object") state = {};

// helpers
const num = (idx) => (Number.isFinite(n[idx]) ? n[idx] : null);
const int = (idx) => {
  const v = num(idx);
  return v == null ? null : Math.trunc(v);
};
const round = (v, d) => {
  const nn = Number(v);
  if (!Number.isFinite(nn)) return null;
  const m = 10 ** d;
  return Math.round(nn * m) / m;
};

// --- apprentissage index pv1_power par node (donc par inverter) ---
let pv1PowerIdx = context.get("pv1PowerIdx"); // mémorisé par node

// ===== QPIGS =====
if (cmd === "QPIGS" && f.length >= 16) {
  // Champs communs (stables)
  if (f.length > 0) state.grid_voltage = round(num(0), 1);
  if (f.length > 1) state.grid_frequency = round(num(1), 1);
  if (f.length > 2) state.ac_output_voltage = round(num(2), 1);
  if (f.length > 3) state.ac_output_frequency = round(num(3), 1);

  // Apparent/active/load : souvent 4/5/6
  if (f.length > 4) state.ac_output_apparent_power = int(4);
  if (f.length > 5) state.ac_output_active_power = int(5);
  if (f.length > 6) state.output_load_percent = int(6);

  // bus voltage : souvent 7
  if (f.length > 7) state.bus_voltage = int(7);

  // ✅ Batterie : tension 2 décimales, courants 1 décimale
  if (f.length > 8) state.battery_voltage = round(num(8), 2);
  if (f.length > 9) state.battery_charging_current = round(num(9), 1);
  if (f.length > 10) state.battery_capacity = int(10);
  if (f.length > 11) state.inverter_heat_sink_temp = int(11);

  // PV entrée : souvent 12/13
  if (f.length > 12) state.pv1_input_current = round(num(12), 1);
  if (f.length > 13) state.pv1_input_voltage = round(num(13), 1);

  // Battery voltage from SCC
  if (f.length > 14) state.battery_voltage_from_scc = round(num(14), 2);

  // Discharge current
  if (f.length > 15) state.battery_discharge_current = round(num(15), 1);

  // ⭐ GLOBAL CURRENT
  const IchgA = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
  const IdisA = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;
  state.global_current = round(IchgA - IdisA, 1);

  // ===== INVERTER OUTPUT CURRENT (A) - calculated =====
  // Approximation: I = P / V (ignores PF). Useful as an indicator.
  const Vac = Number.isFinite(state.ac_output_voltage) ? state.ac_output_voltage : null;
  const Pac = Number.isFinite(state.ac_output_active_power) ? state.ac_output_active_power : null;
  if (Vac != null && Vac > 1 && Pac != null) {
    state.inverter_output_current = Math.round((Pac / Vac) * 10) / 10; // 0.1A
  } else {
    state.inverter_output_current = null;
  }

  // ---- PV1 Power : auto
  if (pv1PowerIdx != null && f.length > pv1PowerIdx) {
    state.pv1_power = int(pv1PowerIdx);
  } else {
    const candidates = [19, 20, 18, 17, 16]; // variantes connues
    for (const idx of candidates) {
      if (f.length > idx && Number.isFinite(n[idx])) {
        const I = state.pv1_input_current;
        const V = state.pv1_input_voltage;
        const pCalc = (Number.isFinite(I) && Number.isFinite(V)) ? (I * V) : null;
        const pField = n[idx];

        if (pCalc != null && pCalc > 10) {
          const ratio = pField / pCalc;
          if (ratio > 0.8 && ratio < 1.2) {
            pv1PowerIdx = idx;
            context.set("pv1PowerIdx", pv1PowerIdx);
            state.pv1_power = int(idx);
            break;
          }
        } else {
          if (idx === 19) {
            state.pv1_power = int(19);
            break;
          }
        }
      }
    }
  }

  // ===== GRID POWER (champ 25 firmwares récents) =====
  // n[24] car index 0-based => "champ 25"
  if (f.length > 24 && Number.isFinite(n[24])) {
    state.grid_power = int(24);
  }

  state._last_qpigs_ts = Date.now();
}

// ===== QPIGS2 (optionnel) =====
if (cmd === "QPIGS2" && f.length >= 3) {
  state.pv2_input_current = round(num(0), 1);
  state.pv2_input_voltage = round(num(1), 1);
  state.pv2_power = int(2);
  state._last_qpigs2_ts = Date.now();
}

// ===== QMOD =====
if (cmd === "QMOD") {
  const rawMode = (f[0] ?? msg.payload.raw ?? "").toString().trim();
  const modeMap = { P: "Power On", S: "Standby", L: "Grid", B: "Battery", F: "Fault" };
  state.operation_mode = modeMap[rawMode] || rawMode || null;
  state.operation_mode_code = rawMode || null;
  state._last_qmod_ts = Date.now();
}

// ===== QPIRI -> PARAMETRES =====
if (cmd === "QPIRI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  const mapBatteryType = (code) => {
    const m = { 0: "AGM", 1: "Flooded", 2: "User", 3: "Pylon", 5: "Weco", 6: "Soltaro", 8: "Lib", 9: "Lic" };
    return m[code] ?? String(code ?? "");
  };
  const mapOutputPriority = (code) => {
    const m = { 0: "UtilitySolarBat", 1: "SolarUtilityBat", 2: "SolarBatUtility" };
    return m[code] ?? String(code ?? "");
  };
  const mapChargerPriority = (code) => {
    const m = { 1: "Solar first", 2: "Solar + Utility", 3: "Only solar" };
    return m[code] ?? String(code ?? "");
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  const battTypeCode = nf(12);
  const outPrioCode = nf(16);
  const chgPrioCode = nf(17);

  state.params.qpiri = {
    battery_recharge_voltage: nf(8),
    battery_under_voltage: nf(9),
    battery_bulk_voltage: nf(10),
    battery_float_voltage: nf(11),

    battery_type_code: battTypeCode,
    battery_type: mapBatteryType(battTypeCode),

    max_ac_charging_current: nf(13),
    max_charging_current: nf(14),

    output_source_priority_code: outPrioCode,
    output_source_priority: mapOutputPriority(outPrioCode),

    charger_source_priority_code: chgPrioCode,
    charger_source_priority: mapChargerPriority(chgPrioCode),

    battery_re_discharge_voltage: nf(22),
    max_discharging_current: nf(27),

    ts: Date.now()
  };

  state._last_qpiri_ts = Date.now();
}

// ===== QDOP -> PARAMETRES batterie (%) =====
if (cmd === "QDOP" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  state.params.qdop = {
    battery_recharge_capacity_pct: nf(8),
    battery_redischarge_capacity_pct: nf(9),
    battery_under_capacity_pct: nf(10),
    ts: Date.now()
  };

  state._last_qdop_ts = Date.now();
}

// ===== DIAGNOSTIC (model/serial/fw + faults/warnings) =====
if (cmd === "QMN" && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.model = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qmn_ts = Date.now();
}

if ((cmd === "QID" || cmd === "QSID") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.serial = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qid_ts = Date.now();
}

if ((cmd === "QVFW" || cmd === "QVFW3") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  const fw = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  if (cmd === "QVFW") state.diag.fw_main = fw;
  if (cmd === "QVFW3") state.diag.fw_remote = fw;
  state._last_qvfw_ts = Date.now();
}

// ===== QPIWS -> FAULTS / WARNINGS (4 lignes HA) =====
if (cmd === "QPIWS" && msg.payload?.nak !== true) {
  const bits = String(f[0] ?? msg.payload.raw ?? "").trim();
  if (!state.diag || typeof state.diag !== "object") state.diag = {};

  const bit = (i) => (bits.length > i ? bits.charAt(i) === "1" : false);
  const a1_fault = bit(1);

  const map = [
    { i: 0, label: "PV loss", kind: "warn" },
    { i: 1, label: "Inverter fault", kind: "fault" },
    { i: 2, label: "Bus over", kind: "fault" },
    { i: 3, label: "Bus under", kind: "fault" },
    { i: 4, label: "Bus soft fail", kind: "fault" },
    { i: 5, label: "Line fail", kind: "warn" },
    { i: 6, label: "OPV short", kind: "fault" },
    { i: 7, label: "Inverter voltage low", kind: "fault" },
    { i: 8, label: "Inverter voltage high", kind: "fault" },
    { i: 9, label: "Over temperature", kind: () => a1_fault ? "fault" : "warn" },
    { i: 10, label: "Fan locked", kind: () => a1_fault ? "fault" : "warn" },
    { i: 11, label: "Battery voltage high", kind: () => a1_fault ? "fault" : "warn" },
    { i: 12, label: "Battery low alarm", kind: "warn" },
    { i: 14, label: "Battery shutdown", kind: "warn" },
    { i: 15, label: "Battery derating", kind: "warn" },
    { i: 16, label: "Over load", kind: () => a1_fault ? "fault" : "warn" },
    { i: 17, label: "EEPROM fault", kind: "warn" },
    { i: 18, label: "Inverter over current", kind: "fault" },
    { i: 19, label: "Inverter soft fail", kind: "fault" },
    { i: 20, label: "Self test fail", kind: "fault" },
    { i: 21, label: "OP DC voltage over", kind: "fault" },
    { i: 23, label: "Current sensor fail", kind: "fault" },
    { i: 33, label: "Low PV energy", kind: "warn" },
    { i: 34, label: "High AC input", kind: "warn" },
    { i: 35, label: "Battery equalization", kind: "warn" }
  ];

  const faults = [];
  const warns = [];

  for (const m of map) {
    if (!bit(m.i)) continue;
    const k = (typeof m.kind === "function") ? m.kind() : m.kind;
    if (k === "fault") faults.push(m.label);
    else warns.push(m.label);
  }

  state.diag.fault_state = faults.length ? "FAULT" : "OK";
  state.diag.fault_details = faults.length ? faults.join(", ") : "None";
  state.diag.warn_state = warns.length ? "WARN" : "OK";
  state.diag.warn_details = warns.length ? warns.join(", ") : "None";
  state.diag.has_fault = faults.length > 0;
  state.diag.has_warning = warns.length > 0;
  state.diag._last_qpiws_ts = Date.now();
}

// ===== Support QPIGS2 (diagnostic) =====
const supportsKey = `inv${inv}_supports_qpigs2`;
const supports = flow.get(supportsKey);
if (supports !== undefined) state.supports_qpigs2 = (supports !== false);

// ===== ENERGIES (FIX Today) =====
const round2 = (v) => (v == null ? null : Math.round(v * 100) / 100);
const toKwhToday = (v) => (!Number.isFinite(v) ? null : round2(v / 1000));
const toKwhAuto = (v) => (!Number.isFinite(v) ? null : (v >= 10000 ? round2(v / 1000) : round2(v)));

if (Number.isFinite(value)) {
  // PV
  if (cmd === "QET") { state.pv_energy_total_raw = value; state.pv_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEY")) { state.pv_energy_year_raw = value; state.pv_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEM")) { state.pv_energy_month_raw = value; state.pv_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QED")) { state.pv_energy_day_raw = value; state.pv_energy_day_kwh = toKwhToday(value); }

  // LOAD
  if (cmd === "QLT") { state.load_energy_total_raw = value; state.load_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLY")) { state.load_energy_year_raw = value; state.load_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLM")) { state.load_energy_month_raw = value; state.load_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLD")) { state.load_energy_day_raw = value; state.load_energy_day_kwh = toKwhToday(value); }

  state._last_energy_ts = Date.now();
}

// ===== PV total power =====
const pv1 = Number.isFinite(state.pv1_power) ? state.pv1_power : 0;
const pv2 = Number.isFinite(state.pv2_power) ? state.pv2_power : 0;
state.pv_total_power = pv1 + pv2;

// ===== BATTERY POWER (W) - CUSTOM SENSORS =====
const Vb = Number.isFinite(state.battery_voltage) ? state.battery_voltage : null;
const Ichg = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
const Idis = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;

if (Vb != null) {
  const chargeW = round(Vb * Math.max(0, Ichg), 1);
  const dischargeW = round(Vb * Math.max(0, Idis), 1);

  state.battery_charge = chargeW;              // +W
  state.battery_discharge = dischargeW;        // +W
  state.battery_power = (chargeW != null && dischargeW != null) ? round(chargeW - dischargeW, 1) : null;
} else {
  state.battery_charge = null;
  state.battery_discharge = null;
  state.battery_power = null;
}

// ===== TIMEZONE dayKey (dynamic) =====
function localDayKey(d = new Date()) {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";
  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return `${get("year")}${get("month")}${get("day")}`; // YYYYMMDD
}

const dayKey = localDayKey(new Date());

// ===== DAILY ENERGY (kWh) - Battery charge/discharge today =====
// Intégration simple (trapèze) sur battery_charge/battery_discharge (W)

const kDay = `inv${inv}_batt_dayKey`;
const kTs  = `inv${inv}_batt_lastTs`;
const kChg = `inv${inv}_batt_lastChargeW`;
const kDis = `inv${inv}_batt_lastDischargeW`;
const kChgWh = `inv${inv}_batt_chargeWh_today`;
const kDisWh = `inv${inv}_batt_dischargeWh_today`;

const lastDay = flow.get(kDay);
let lastTs = flow.get(kTs);
let lastChargeW = flow.get(kChg);
let lastDischargeW = flow.get(kDis);

let chargeWh = flow.get(kChgWh);
let dischargeWh = flow.get(kDisWh);

if (!Number.isFinite(chargeWh)) chargeWh = 0;
if (!Number.isFinite(dischargeWh)) dischargeWh = 0;

// Reset si on change de jour
if (lastDay && lastDay !== dayKey) {
  chargeWh = 0;
  dischargeWh = 0;
}

// Puissances actuelles (W) - déjà positives chez toi
const curChargeW = Number.isFinite(state.battery_charge) ? state.battery_charge : 0;
const curDischargeW = Number.isFinite(state.battery_discharge) ? state.battery_discharge : 0;

const nowTs = Date.now();

if (Number.isFinite(lastTs) && Number.isFinite(lastChargeW) && Number.isFinite(lastDischargeW)) {
  const dtMs = nowTs - lastTs;
  // ignore si dt délirant (redémarrage / horloge) : > 10 minutes
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    chargeWh += ((lastChargeW + curChargeW) / 2) * dtH;
    dischargeWh += ((lastDischargeW + curDischargeW) / 2) * dtH;
  }
}

// Stocke contexte
flow.set(kDay, dayKey);
flow.set(kTs, nowTs);
flow.set(kChg, curChargeW);
flow.set(kDis, curDischargeW);
flow.set(kChgWh, chargeWh);
flow.set(kDisWh, dischargeWh);

// Expose dans state en kWh
state.battery_charge_day_kwh = Math.round((chargeWh / 1000) * 100) / 100;
state.battery_discharge_day_kwh = Math.round((dischargeWh / 1000) * 100) / 100;
state._day_key = dayKey; // debug optionnel

// ===== FILTRE ANTI-SPIKE (W) =====
const MAX_W = 15000;

function finiteNumber(x) {
  const nn = Number(x);
  return Number.isFinite(nn) ? nn : null;
}

function clampAbs(x, maxAbs) {
  if (x == null) return null;
  if (Math.abs(x) <= maxAbs) return x;
  return x < 0 ? -maxAbs : maxAbs;
}

// garde dernière valeur OK par inv + key
function sanitizeW(key, { maxAbs = MAX_W, allowNegative = true, forceNonNegative = false } = {}) {
  const v = finiteNumber(state[key]);
  if (v == null) return;

  // force >=0 si demandé
  let vv = v;
  if (forceNonNegative && vv < 0) vv = 0;

  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  // hors limite -> lastOk sinon clamp
  if (Math.abs(vv) > maxAbs) {
    if (lastOk != null && Number.isFinite(lastOk)) {
      state[key] = lastOk;
    } else {
      state[key] = clampAbs(vv, maxAbs);
    }
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, maxAbs });
    return;
  }

  // interdit négatif
  if (!allowNegative && vv < 0) {
    state[key] = (lastOk != null && Number.isFinite(lastOk)) ? lastOk : 0;
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, reason: "negative_not_allowed" });
    return;
  }

  // OK -> mémorise
  state[key] = vv;
  flow.set(lastKey, vv);
}

// Champs demandés
sanitizeW("ac_output_active_power", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("grid_power", { maxAbs: MAX_W, allowNegative: true });
sanitizeW("battery_charge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_discharge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_power", { maxAbs: MAX_W, allowNegative: true });

// ===== GRID TODAY (kWh) - from grid_power (W) =====
// Intégration trapèze + reset journalier selon timezone config
// On compte uniquement l'import (si grid_power négatif => 0)

const kGDay = `inv${inv}_grid_dayKey`;
const kGTs  = `inv${inv}_grid_lastTs`;
const kGLastW = `inv${inv}_grid_lastW`;
const kGWh = `inv${inv}_grid_Wh_today`;

let gLastDay = flow.get(kGDay);
let gLastTs = flow.get(kGTs);
let gLastW = flow.get(kGLastW);
let gWh = flow.get(kGWh);

if (!Number.isFinite(gWh)) gWh = 0;

// reset jour
if (gLastDay && gLastDay !== dayKey) {
  gWh = 0;
}

// puissance grid actuelle (import only)
const gCurW_raw = Number.isFinite(state.grid_power) ? state.grid_power : 0;
const gCurW = Math.max(0, gCurW_raw);

const gNowTs = Date.now();

if (Number.isFinite(gLastTs) && Number.isFinite(gLastW)) {
  const dtMs = gNowTs - gLastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    gWh += ((gLastW + gCurW) / 2) * dtH;
  }
}

flow.set(kGDay, dayKey);
flow.set(kGTs, gNowTs);
flow.set(kGLastW, gCurW);
flow.set(kGWh, gWh);

// expose en kWh (2 décimales)
state.grid_energy_day_kwh = Math.round((gWh / 1000) * 100) / 100;

context.set("state", state);
msg.inverterNum = inv;
msg.payload = state;
return msg;

// ===============================
// MQTT STATE PUBLISHER (STABLE JSON)
// Garantit une structure toujours identique
// ===============================

if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? 1;
const data = { ...msg.payload };

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const ensure = (obj, key, value = null) => {
    if (obj[key] === undefined) obj[key] = value;
};

// -------------------------------------------------
// 1) STRUCTURE PRINCIPALE
// -------------------------------------------------
ensure(data, "grid_voltage");
ensure(data, "grid_frequency");
ensure(data, "ac_output_voltage");
ensure(data, "ac_output_frequency");
ensure(data, "ac_output_active_power");
ensure(data, "output_load_percent");

ensure(data, "battery_voltage");
ensure(data, "battery_charging_current");
ensure(data, "battery_discharge_current");
ensure(data, "battery_capacity");

ensure(data, "battery_charge");
ensure(data, "battery_discharge");
ensure(data, "battery_power");

ensure(data, "pv_total_power");
ensure(data, "pv1_power");
ensure(data, "pv2_power");

ensure(data, "pv1_input_voltage");
ensure(data, "pv2_input_voltage");
ensure(data, "pv1_input_current");
ensure(data, "pv2_input_current");

ensure(data, "grid_power");
ensure(data, "inverter_heat_sink_temp");

ensure(data, "operation_mode");

// -------------------------------------------------
// 2) ENERGIES (souvent absentes selon timing)
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag) data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");
ensure(data.diag, "fault_state", "unknown");
ensure(data.diag, "fault_details", "unknown");
ensure(data.diag, "warn_state", "unknown");
ensure(data.diag, "warn_details", "unknown");

// -------------------------------------------------
// 4) PARAMS (CRITIQUE POUR SELECT/NUMBER)
// -------------------------------------------------
if (!data.params) data.params = {};
if (!data.params.qpiri) data.params.qpiri = {};
if (!data.params.qdop) data.params.qdop = {};

// valeurs null si pas encore connues (HA ne plantera plus)
const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "output_source_priority");
ensure(qpiri, "charger_source_priority");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

ensure(qpiri, "max_ac_charging_current");
ensure(qpiri, "max_charging_current");
ensure(qpiri, "max_discharging_current");

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");

// -------------------------------------------------
// 5) PUBLISH MQTT
// -------------------------------------------------
return [
    {
        topic: `voltronic/${inv}/state`,
        payload: JSON.stringify(data),
        retain: true
    },
    {
        topic: `voltronic/${inv}/availability`,
        payload: "online",
        retain: true
    }
];

const inv = msg.inverterNum ?? 1;
const key = `inv${inv}_queue`;

let q = flow.get(key);
if (!Array.isArray(q)) q = [];

// msg peut être 1 commande, ou un lot (si tu envoies [msgs])
// Ici, on gère les deux cas proprement.
const toPush = [];

if (Array.isArray(msg)) {
    // rare : si tu envoies direct un tableau de msgs
    toPush.push(...msg);
} else if (Array.isArray(msg.payload) && msg.payload?.[0]?.command) {
    // si jamais ton flow passe un tableau dans payload
    toPush.push(...msg.payload);
} else {
    // msg normal
    toPush.push(msg);
}

// ajoute uniquement si on a une commande
toPush.forEach(m => {
    const cmd = (m.command || m._cmd || m.payload || "").toString().trim().toUpperCase();
    if (!cmd) return;

    q.push({
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        payload: cmd,
        enqueued_ts: Date.now()
    });
});

// limite taille
if (q.length > 200) q = q.slice(-200);

flow.set(key, q);

// déclenche le pump
return { inverterNum: inv, topic: "pump" };

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let inFlight = flow.get(inFlightKey);

// Si une commande est déjà en attente de réponse, on n’en envoie pas une autre
if (inFlight && (Date.now() - (inFlight.ts || 0)) < 3000) {
  return null;
}

let q = flow.get(qKey);
if (!Array.isArray(q) || q.length === 0) return null;

// Prend la prochaine commande
const next = q.shift();
flow.set(qKey, q);

// Marque comme en vol
flow.set(inFlightKey, { cmd: next.command, ts: Date.now() });

// Envoie au construire commande
return next;

// ====== CONSTRUIRE COMMANDE (Voltronic) ======
const helpers = global.get("helpers");

if (!helpers || typeof helpers.buildVoltronicCommand !== "function") {
  node.error("helpers.buildVoltronicCommand introuvable (global.helpers)");
  return null;
}

// Récupère la commande (priorité à msg.command)
let cmd = (msg.command ?? msg._cmd ?? msg.payload ?? "")
  .toString()
  .trim();

// ------------------------------
// FIX: commandes qui arrivent avec guillemets
// ex: '"PBATMAXDISC150"' ou 'PBATMAXDISC150""'
// ------------------------------

// si c'est du JSON stringifié (ex: "\"PBATMAXDISC150\""), tente parse
try {
  if (cmd.startsWith('"') || cmd.startsWith('\\"')) {
    const parsed = JSON.parse(cmd);
    if (typeof parsed === "string") cmd = parsed;
  }
} catch (e) {
  // ignore
}

// retire guillemets parasites au début/fin
cmd = cmd.trim().replace(/^"+|"+$/g, "");

// upper après nettoyage
cmd = cmd.toUpperCase();

if (!cmd) {
  node.warn("Commande vide -> ignorée");
  return null;
}

/*
  Validation "safe" :
  - Requêtes classiques: QPIGS, QPIRI, QMOD, QET, QLD20260220, etc.
  - SET Voltronic: souvent Pxxxx + valeur (ex: PCVV55.7, PBT02, PBATMAXDISC150, etc.)
  On autorise uniquement: A-Z / 0-9 / '.' / '-' et on contrôle les patterns.
*/
const isQueryOrStat =
  /^[A-Z]{2,6}[0-9]*$/.test(cmd); // ex: QPIGS, QPIRI, QET, QED20260220, QEY2026...

const isSetWithValue =
  /^P[A-Z0-9]{2,12}-?[0-9]+(\.[0-9]+)?$/.test(cmd);
// ↑ élargi à 2..12 (PBATMAXDISC = 10 lettres après P)

// IMPORTANT: PBATMAXDISC est un SET spécial avec 3 digits, ex: PBATMAXDISC150
// Il match déjà la regex ci-dessus, mais on garde ce commentaire pour clarté.

if (!isQueryOrStat && !isSetWithValue) {
  node.warn(`Commande invalide ignorée: "${cmd}"`);
  return null;
}

// Conserver la commande envoyée (utile pour associer RX)
msg.command = cmd;
msg._cmd = cmd;

// Construire la trame (CRC + CR)
let buf;
try {
  buf = helpers.buildVoltronicCommand(cmd);
} catch (e) {
  node.error(`Erreur buildVoltronicCommand("${cmd}") : ${e.message || e}`);
  return null;
}

// Payload = Buffer à envoyer dans Serial Out
msg.payload = buf;

// Debug utile
msg._tx_ts = Date.now();
msg._tx_ascii = cmd;
msg._tx_hex = buf.toString("hex");

// Status (optionnel)
node.status({
  fill: "blue",
  shape: "dot",
  text: `${cmd} → ond${msg.inverterNum ?? "?"}`
});

// Mémorise la dernière commande par onduleur (utile RX/timeout)
if (msg.inverterNum != null) {
  flow.set(`inv${msg.inverterNum}_last_cmd`, msg._cmd);
  flow.set(`inv${msg.inverterNum}_last_cmd_ts`, Date.now());
}

return msg;

// ====== REQUETES (Option A + firstRun + force + QPIGS2 auto-disable + retry 1h + DIAG) ======
// ✅ Fix: QPIRI/QDOP + DIAG/FW bien envoyés AU BOOT
// ✅ Fix: Burst boot exécuté AVANT le tick realtime (évite “perte” si queue/pump limité)
// ✅ Garde ta logique QPIGS2 auto-disable + retry 1h

const inverterNum = 2;
const ts = Date.now();
const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());

const yyyymm = `${yyyy}${mm}`;
const yyyymmdd = `${yyyy}${mm}${dd}`;

// état alternance
let alt = context.get("alt");
if (alt === undefined || alt === null) alt = 0;

// firstRun peut rester false si context persistant
let firstRun = context.get("firstRun");
if (firstRun === undefined) firstRun = true;

// Permet de forcer un burst via un inject bouton (msg.forceFirstRun=true)
if (msg && msg.forceFirstRun === true) {
  firstRun = true;
}

// timers existants
let nextQMOD = context.get("nextQMOD");
let nextHour = context.get("nextHour");
let nextDay10m = context.get("nextDay10m");
let nextMonth6 = context.get("nextMonth6");
let nextYear24 = context.get("nextYear24");

// timers params
let nextQPIRI = context.get("nextQPIRI");
let nextQDOP = context.get("nextQDOP");

// retry QPIGS2 même si désactivé
let nextRetryQPIGS2 = context.get("nextRetryQPIGS2");
if (!nextRetryQPIGS2) nextRetryQPIGS2 = ts + 60 * 60 * 1000;

// ✅ DIAG timers
let diagDone = context.get("diagDone");           // 1-shot after boot (flag)
let nextQPIWS = context.get("nextQPIWS");         // 5 min

function makeCmd(cmd) {
  return { inverterNum, command: cmd, _cmd: cmd, payload: cmd };
}

const msgs = [];

// ----- QPIGS/QPIGS2 stratégie -----
const supportsQPIGS2 = flow.get(`inv${inverterNum}_supports_qpigs2`);
const useQPIGS2 = (supportsQPIGS2 !== false);

function pushRealtimeTick() {
  if (useQPIGS2) {
    msgs.push(makeCmd(alt === 0 ? "QPIGS" : "QPIGS2"));
    alt = alt ? 0 : 1;
  } else {
    msgs.push(makeCmd("QPIGS"));
    if (ts >= nextRetryQPIGS2) {
      msgs.push(makeCmd("QPIGS2"));
      nextRetryQPIGS2 = ts + 60 * 60 * 1000;
    }
  }
}

// =========================
// 1) BOOT BURST (firstRun)
// =========================
if (firstRun) {
  const burst = [
    // ✅ PARAMS AU BOOT (sinon tu attends 5 minutes)
    "QPIRI",
    "QDOP",

    // realtime info utile
    "QMOD",

    // energies
    "QET", `QEY${yyyy}`, `QEM${yyyymm}`, `QED${yyyymmdd}`,
    "QLT", `QLY${yyyy}`, `QLM${yyyymm}`, `QLD${yyyymmdd}`,

    // ✅ DIAG au boot
    "QMN",      // model
    "QID",      // serial (si besoin: remplacer par QSID)
    "QVFW",     // fw main
    "QVFW3",    // fw remote/panel (si supporté)
    "QPIWS"     // warnings/faults (1er état)
  ];

  burst.forEach(c => msgs.push(makeCmd(c)));

  // Schedules
  nextQMOD = ts + 5 * 60 * 1000;
  nextHour = ts + 60 * 60 * 1000;
  nextDay10m = ts + 10 * 60 * 1000;
  nextMonth6 = ts + 6 * 60 * 60 * 1000;
  nextYear24 = ts + 24 * 60 * 60 * 1000;

  // ✅ Tu viens de les envoyer -> replanifie à +5 minutes
  nextQPIRI = ts + 5 * 60 * 1000;
  nextQDOP = ts + 5 * 60 * 1000;

  // ✅ DIAG flags/timers
  diagDone = true;
  nextQPIWS = ts + 5 * 60 * 1000;

  firstRun = false;

  node.status({ fill: "green", shape: "dot", text: `FIRST RUN: ${msgs.length} cmds` });
}

// =========================
// 2) NORMAL MODE (timers)
// =========================
else {
  // QMOD 5 min
  if (nextQMOD == null) nextQMOD = ts + 5 * 60 * 1000;
  if (ts >= nextQMOD) {
    msgs.push(makeCmd("QMOD"));
    nextQMOD = ts + 5 * 60 * 1000;
  }

  // QPIRI 5 min
  if (nextQPIRI == null) nextQPIRI = ts + 5 * 60 * 1000;
  if (ts >= nextQPIRI) {
    msgs.push(makeCmd("QPIRI"));
    nextQPIRI = ts + 5 * 60 * 1000;
  }

  // QDOP 5 min
  if (nextQDOP == null) nextQDOP = ts + 5 * 60 * 1000;
  if (ts >= nextQDOP) {
    msgs.push(makeCmd("QDOP"));
    nextQDOP = ts + 5 * 60 * 1000;
  }

  // ✅ QPIWS (fault/warnings) 5 min
  if (nextQPIWS == null) nextQPIWS = ts + 5 * 60 * 1000;
  if (ts >= nextQPIWS) {
    msgs.push(makeCmd("QPIWS"));
    nextQPIWS = ts + 5 * 60 * 1000;
  }

  // Hourly
  if (nextHour == null) nextHour = ts + 60 * 60 * 1000;
  if (ts >= nextHour) {
    // énergies (total)
    msgs.push(makeCmd("QET"));
    msgs.push(makeCmd("QLT"));

    // diagnostics (1 fois/heure)
    msgs.push(makeCmd("QMN"));
    msgs.push(makeCmd("QID"));
    msgs.push(makeCmd("QVFW"));
    msgs.push(makeCmd("QVFW3"));

    nextHour = ts + 60 * 60 * 1000;
  }

  // Daily 10min
  if (nextDay10m == null) nextDay10m = ts + 10 * 60 * 1000;
  if (ts >= nextDay10m) {
    msgs.push(makeCmd(`QED${yyyymmdd}`));
    msgs.push(makeCmd(`QLD${yyyymmdd}`));
    nextDay10m = ts + 10 * 60 * 1000;
  }

  // Monthly 6h
  if (nextMonth6 == null) nextMonth6 = ts + 6 * 60 * 60 * 1000;
  if (ts >= nextMonth6) {
    msgs.push(makeCmd(`QEM${yyyymm}`));
    msgs.push(makeCmd(`QLM${yyyymm}`));
    nextMonth6 = ts + 6 * 60 * 60 * 1000;
  }

  // Yearly 24h
  if (nextYear24 == null) nextYear24 = ts + 24 * 60 * 60 * 1000;
  if (ts >= nextYear24) {
    msgs.push(makeCmd(`QEY${yyyy}`));
    msgs.push(makeCmd(`QLY${yyyy}`));
    nextYear24 = ts + 24 * 60 * 60 * 1000;
  }
}

// =========================
// 3) REALTIME TICK (toujours à la fin)
// =========================
pushRealtimeTick();

// =========================
// save context
// =========================
context.set("alt", alt);
context.set("firstRun", firstRun);
context.set("nextQMOD", nextQMOD);
context.set("nextHour", nextHour);
context.set("nextDay10m", nextDay10m);
context.set("nextMonth6", nextMonth6);
context.set("nextYear24", nextYear24);
context.set("nextQPIRI", nextQPIRI);
context.set("nextQDOP", nextQDOP);
context.set("nextRetryQPIGS2", nextRetryQPIGS2);

// ✅ save DIAG
context.set("diagDone", diagDone);
context.set("nextQPIWS", nextQPIWS);

return [msgs];

// ====== PARSER 1 (Voltronic) - QUEUE MODE ======
// Entrée: msg.payload = Buffer (Serial IN en "a single buffer", pas de split)
// Sorties:
//   1) trigger pump (msg.topic="pump")
//   2) data parsée (vers normalize state)
// Associe la réponse à la commande "inflight" (envoyée par Queue Pump)

const inv = msg.inverterNum ?? 1;
if (!Buffer.isBuffer(msg.payload)) return null;

// --- accumulateur RX ---
let rx = context.get("rxbuf");
if (!Buffer.isBuffer(rx)) rx = Buffer.alloc(0);

// sécurité overflow
if (rx.length > 8192) rx = Buffer.alloc(0);

// concat
rx = Buffer.concat([rx, msg.payload]);

const CR = 0x0D;

// extrait toutes les frames finissant par CR
const frames = [];
while (true) {
  const idx = rx.indexOf(CR);
  if (idx === -1) break;
  frames.push(rx.slice(0, idx + 1));
  rx = rx.slice(idx + 1);
}
context.set("rxbuf", rx);

if (!frames.length) return null;

// commande inflight (celle réellement envoyée)
const inflightKey = `inv${inv}_inflight`;
const inflight = flow.get(inflightKey);
const inflightCmd = inflight?.cmd || "UNKNOWN";

// Nettoyage trame -> ASCII sans CRC/CR
function cleanAsciiFromFrame(frameBuf) {
  // NAK brut possible (0x15)
  if (frameBuf.length === 1 && frameBuf[0] === 0x15) return "NAK";

  // Normalement: <data ASCII> + <CRC 2 bytes> + <CR>
  let dataBuf = frameBuf;

  if (frameBuf.length >= 3 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -3); // retire CRC(2) + CR(1)
  } else if (frameBuf.length >= 1 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -1); // fallback retire CR
  }

  return dataBuf.toString("ascii");
}

function parseFrame(frameBuf, cmd) {
  const ascii = cleanAsciiFromFrame(frameBuf);

  // Détection NAK "NAK" ou 0x15
  if (ascii.includes("NAK") || ascii === "NAK") {
    return {
      inverter: inv,
      command: cmd,
      nak: true,
      raw: "NAK",
      fields: [],
      nums: [],
      value: null
    };
  }

  // Enlever parenthèses si présentes
  let body = ascii.trim();
  if (body.startsWith("(")) body = body.slice(1);
  if (body.endsWith(")")) body = body.slice(0, -1);
  body = body.trim();

  const fields = body.length ? body.split(/\s+/) : [];
  const nums = fields.map(v => {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  });

  // Cas énergie (1 valeur)
  const isEnergyCmd = /^Q(E[TYMD]|L[TYMD])/.test(cmd);
  let value = null;
  if (isEnergyCmd && fields.length >= 1) {
    const n0 = Number(fields[0]);
    if (Number.isFinite(n0)) value = n0;
  }

  return {
    inverter: inv,
    command: cmd,
    raw: body,
    fields,
    nums,
    value
  };
}

// Ici, on part du principe QUEUE = 1 commande envoyée -> 1 réponse attendue.
// Mais on gère quand même le cas "plusieurs frames d'un coup" :
// - 1ère frame = inflightCmd
// - frames suivantes = UNKNOWN (ou on garde inflightCmd si tu préfères)
const outMsgs = [];
for (let i = 0; i < frames.length; i++) {
  const cmd = (i === 0) ? inflightCmd : "UNKNOWN";
  outMsgs.push({
    inverterNum: inv,
    _cmd: cmd,
    command: cmd,
    payload: parseFrame(frames[i], cmd),
    _rx_ts: Date.now()
  });
}

// ACK : dès qu'on reçoit au moins une frame, on libère inflight
flow.set(inflightKey, null);

// Trigger pump immédiatement (pour envoyer la prochaine commande)
const pumpMsg = { inverterNum: inv, topic: "pump" };

// Sortie 1: pump trigger
// Sortie 2: data parsée (plusieurs messages possibles)
return [[pumpMsg], outMsgs];

// ====== NORMALIZE STATE (AUTO / MULTI-MODEL) - + TZ dynamic + GRID TODAY ======
if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? msg.payload.inverter ?? 1;

// Normaliser la commande (évite "QPIRI\r", "qpiri", "QPIRI ")
const cmd = String(msg.payload.command || msg.command || msg._cmd || "UNKNOWN")
  .trim()
  .toUpperCase();

const f = Array.isArray(msg.payload.fields) ? msg.payload.fields : [];
const n = Array.isArray(msg.payload.nums) ? msg.payload.nums : [];
const value = msg.payload.value;

let state = context.get("state");
if (!state || typeof state !== "object") state = {};

// helpers
const num = (idx) => (Number.isFinite(n[idx]) ? n[idx] : null);
const int = (idx) => {
  const v = num(idx);
  return v == null ? null : Math.trunc(v);
};
const round = (v, d) => {
  const nn = Number(v);
  if (!Number.isFinite(nn)) return null;
  const m = 10 ** d;
  return Math.round(nn * m) / m;
};

// --- apprentissage index pv1_power par node (donc par inverter) ---
let pv1PowerIdx = context.get("pv1PowerIdx"); // mémorisé par node

// ===== QPIGS =====
if (cmd === "QPIGS" && f.length >= 16) {
  // Champs communs (stables)
  if (f.length > 0) state.grid_voltage = round(num(0), 1);
  if (f.length > 1) state.grid_frequency = round(num(1), 1);
  if (f.length > 2) state.ac_output_voltage = round(num(2), 1);
  if (f.length > 3) state.ac_output_frequency = round(num(3), 1);

  // Apparent/active/load : souvent 4/5/6
  if (f.length > 4) state.ac_output_apparent_power = int(4);
  if (f.length > 5) state.ac_output_active_power = int(5);
  if (f.length > 6) state.output_load_percent = int(6);

  // bus voltage : souvent 7
  if (f.length > 7) state.bus_voltage = int(7);

  // ✅ Batterie : tension 2 décimales, courants 1 décimale
  if (f.length > 8) state.battery_voltage = round(num(8), 2);
  if (f.length > 9) state.battery_charging_current = round(num(9), 1);
  if (f.length > 10) state.battery_capacity = int(10);
  if (f.length > 11) state.inverter_heat_sink_temp = int(11);

  // PV entrée : souvent 12/13
  if (f.length > 12) state.pv1_input_current = round(num(12), 1);
  if (f.length > 13) state.pv1_input_voltage = round(num(13), 1);

  // Battery voltage from SCC
  if (f.length > 14) state.battery_voltage_from_scc = round(num(14), 2);

  // Discharge current
  if (f.length > 15) state.battery_discharge_current = round(num(15), 1);

  // ⭐ GLOBAL CURRENT
  const IchgA = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
  const IdisA = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;
  state.global_current = round(IchgA - IdisA, 1);

  // ===== INVERTER OUTPUT CURRENT (A) - calculated =====
  // Approximation: I = P / V (ignores PF). Useful as an indicator.
  const Vac = Number.isFinite(state.ac_output_voltage) ? state.ac_output_voltage : null;
  const Pac = Number.isFinite(state.ac_output_active_power) ? state.ac_output_active_power : null;
  if (Vac != null && Vac > 1 && Pac != null) {
    state.inverter_output_current = Math.round((Pac / Vac) * 10) / 10; // 0.1A
  } else {
    state.inverter_output_current = null;
  }

  // ---- PV1 Power : auto
  if (pv1PowerIdx != null && f.length > pv1PowerIdx) {
    state.pv1_power = int(pv1PowerIdx);
  } else {
    const candidates = [19, 20, 18, 17, 16]; // variantes connues
    for (const idx of candidates) {
      if (f.length > idx && Number.isFinite(n[idx])) {
        const I = state.pv1_input_current;
        const V = state.pv1_input_voltage;
        const pCalc = (Number.isFinite(I) && Number.isFinite(V)) ? (I * V) : null;
        const pField = n[idx];

        if (pCalc != null && pCalc > 10) {
          const ratio = pField / pCalc;
          if (ratio > 0.8 && ratio < 1.2) {
            pv1PowerIdx = idx;
            context.set("pv1PowerIdx", pv1PowerIdx);
            state.pv1_power = int(idx);
            break;
          }
        } else {
          if (idx === 19) {
            state.pv1_power = int(19);
            break;
          }
        }
      }
    }
  }

  // ===== GRID POWER (champ 25 firmwares récents) =====
  // n[24] car index 0-based => "champ 25"
  if (f.length > 24 && Number.isFinite(n[24])) {
    state.grid_power = int(24);
  }

  state._last_qpigs_ts = Date.now();
}

// ===== QPIGS2 (optionnel) =====
if (cmd === "QPIGS2" && f.length >= 3) {
  state.pv2_input_current = round(num(0), 1);
  state.pv2_input_voltage = round(num(1), 1);
  state.pv2_power = int(2);
  state._last_qpigs2_ts = Date.now();
}

// ===== QMOD =====
if (cmd === "QMOD") {
  const rawMode = (f[0] ?? msg.payload.raw ?? "").toString().trim();
  const modeMap = { P: "Power On", S: "Standby", L: "Grid", B: "Battery", F: "Fault" };
  state.operation_mode = modeMap[rawMode] || rawMode || null;
  state.operation_mode_code = rawMode || null;
  state._last_qmod_ts = Date.now();
}

// ===== QPIRI -> PARAMETRES =====
if (cmd === "QPIRI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  const mapBatteryType = (code) => {
    const m = { 0: "AGM", 1: "Flooded", 2: "User", 3: "Pylon", 5: "Weco", 6: "Soltaro", 8: "Lib", 9: "Lic" };
    return m[code] ?? String(code ?? "");
  };
  const mapOutputPriority = (code) => {
    const m = { 0: "UtilitySolarBat", 1: "SolarUtilityBat", 2: "SolarBatUtility" };
    return m[code] ?? String(code ?? "");
  };
  const mapChargerPriority = (code) => {
    const m = { 1: "Solar first", 2: "Solar + Utility", 3: "Only solar" };
    return m[code] ?? String(code ?? "");
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  const battTypeCode = nf(12);
  const outPrioCode = nf(16);
  const chgPrioCode = nf(17);

  state.params.qpiri = {
    battery_recharge_voltage: nf(8),
    battery_under_voltage: nf(9),
    battery_bulk_voltage: nf(10),
    battery_float_voltage: nf(11),

    battery_type_code: battTypeCode,
    battery_type: mapBatteryType(battTypeCode),

    max_ac_charging_current: nf(13),
    max_charging_current: nf(14),

    output_source_priority_code: outPrioCode,
    output_source_priority: mapOutputPriority(outPrioCode),

    charger_source_priority_code: chgPrioCode,
    charger_source_priority: mapChargerPriority(chgPrioCode),

    battery_re_discharge_voltage: nf(22),
    max_discharging_current: nf(27),

    ts: Date.now()
  };

  state._last_qpiri_ts = Date.now();
}

// ===== QDOP -> PARAMETRES batterie (%) =====
if (cmd === "QDOP" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  state.params.qdop = {
    battery_recharge_capacity_pct: nf(8),
    battery_redischarge_capacity_pct: nf(9),
    battery_under_capacity_pct: nf(10),
    ts: Date.now()
  };

  state._last_qdop_ts = Date.now();
}

// ===== DIAGNOSTIC (model/serial/fw + faults/warnings) =====
if (cmd === "QMN" && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.model = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qmn_ts = Date.now();
}

if ((cmd === "QID" || cmd === "QSID") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.serial = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qid_ts = Date.now();
}

if ((cmd === "QVFW" || cmd === "QVFW3") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  const fw = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  if (cmd === "QVFW") state.diag.fw_main = fw;
  if (cmd === "QVFW3") state.diag.fw_remote = fw;
  state._last_qvfw_ts = Date.now();
}

// ===== QPIWS -> FAULTS / WARNINGS (4 lignes HA) =====
if (cmd === "QPIWS" && msg.payload?.nak !== true) {
  const bits = String(f[0] ?? msg.payload.raw ?? "").trim();
  if (!state.diag || typeof state.diag !== "object") state.diag = {};

  const bit = (i) => (bits.length > i ? bits.charAt(i) === "1" : false);
  const a1_fault = bit(1);

  const map = [
    { i: 0, label: "PV loss", kind: "warn" },
    { i: 1, label: "Inverter fault", kind: "fault" },
    { i: 2, label: "Bus over", kind: "fault" },
    { i: 3, label: "Bus under", kind: "fault" },
    { i: 4, label: "Bus soft fail", kind: "fault" },
    { i: 5, label: "Line fail", kind: "warn" },
    { i: 6, label: "OPV short", kind: "fault" },
    { i: 7, label: "Inverter voltage low", kind: "fault" },
    { i: 8, label: "Inverter voltage high", kind: "fault" },
    { i: 9, label: "Over temperature", kind: () => a1_fault ? "fault" : "warn" },
    { i: 10, label: "Fan locked", kind: () => a1_fault ? "fault" : "warn" },
    { i: 11, label: "Battery voltage high", kind: () => a1_fault ? "fault" : "warn" },
    { i: 12, label: "Battery low alarm", kind: "warn" },
    { i: 14, label: "Battery shutdown", kind: "warn" },
    { i: 15, label: "Battery derating", kind: "warn" },
    { i: 16, label: "Over load", kind: () => a1_fault ? "fault" : "warn" },
    { i: 17, label: "EEPROM fault", kind: "warn" },
    { i: 18, label: "Inverter over current", kind: "fault" },
    { i: 19, label: "Inverter soft fail", kind: "fault" },
    { i: 20, label: "Self test fail", kind: "fault" },
    { i: 21, label: "OP DC voltage over", kind: "fault" },
    { i: 23, label: "Current sensor fail", kind: "fault" },
    { i: 33, label: "Low PV energy", kind: "warn" },
    { i: 34, label: "High AC input", kind: "warn" },
    { i: 35, label: "Battery equalization", kind: "warn" }
  ];

  const faults = [];
  const warns = [];

  for (const m of map) {
    if (!bit(m.i)) continue;
    const k = (typeof m.kind === "function") ? m.kind() : m.kind;
    if (k === "fault") faults.push(m.label);
    else warns.push(m.label);
  }

  state.diag.fault_state = faults.length ? "FAULT" : "OK";
  state.diag.fault_details = faults.length ? faults.join(", ") : "None";
  state.diag.warn_state = warns.length ? "WARN" : "OK";
  state.diag.warn_details = warns.length ? warns.join(", ") : "None";
  state.diag.has_fault = faults.length > 0;
  state.diag.has_warning = warns.length > 0;
  state.diag._last_qpiws_ts = Date.now();
}

// ===== Support QPIGS2 (diagnostic) =====
const supportsKey = `inv${inv}_supports_qpigs2`;
const supports = flow.get(supportsKey);
if (supports !== undefined) state.supports_qpigs2 = (supports !== false);

// ===== ENERGIES (FIX Today) =====
const round2 = (v) => (v == null ? null : Math.round(v * 100) / 100);
const toKwhToday = (v) => (!Number.isFinite(v) ? null : round2(v / 1000));
const toKwhAuto = (v) => (!Number.isFinite(v) ? null : (v >= 10000 ? round2(v / 1000) : round2(v)));

if (Number.isFinite(value)) {
  // PV
  if (cmd === "QET") { state.pv_energy_total_raw = value; state.pv_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEY")) { state.pv_energy_year_raw = value; state.pv_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEM")) { state.pv_energy_month_raw = value; state.pv_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QED")) { state.pv_energy_day_raw = value; state.pv_energy_day_kwh = toKwhToday(value); }

  // LOAD
  if (cmd === "QLT") { state.load_energy_total_raw = value; state.load_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLY")) { state.load_energy_year_raw = value; state.load_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLM")) { state.load_energy_month_raw = value; state.load_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLD")) { state.load_energy_day_raw = value; state.load_energy_day_kwh = toKwhToday(value); }

  state._last_energy_ts = Date.now();
}

// ===== PV total power =====
const pv1 = Number.isFinite(state.pv1_power) ? state.pv1_power : 0;
const pv2 = Number.isFinite(state.pv2_power) ? state.pv2_power : 0;
state.pv_total_power = pv1 + pv2;

// ===== BATTERY POWER (W) - CUSTOM SENSORS =====
const Vb = Number.isFinite(state.battery_voltage) ? state.battery_voltage : null;
const Ichg = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
const Idis = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;

if (Vb != null) {
  const chargeW = round(Vb * Math.max(0, Ichg), 1);
  const dischargeW = round(Vb * Math.max(0, Idis), 1);

  state.battery_charge = chargeW;              // +W
  state.battery_discharge = dischargeW;        // +W
  state.battery_power = (chargeW != null && dischargeW != null) ? round(chargeW - dischargeW, 1) : null;
} else {
  state.battery_charge = null;
  state.battery_discharge = null;
  state.battery_power = null;
}

// ===== TIMEZONE dayKey (dynamic) =====
function localDayKey(d = new Date()) {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";
  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return `${get("year")}${get("month")}${get("day")}`; // YYYYMMDD
}

const dayKey = localDayKey(new Date());

// ===== DAILY ENERGY (kWh) - Battery charge/discharge today =====
// Intégration simple (trapèze) sur battery_charge/battery_discharge (W)

const kDay = `inv${inv}_batt_dayKey`;
const kTs  = `inv${inv}_batt_lastTs`;
const kChg = `inv${inv}_batt_lastChargeW`;
const kDis = `inv${inv}_batt_lastDischargeW`;
const kChgWh = `inv${inv}_batt_chargeWh_today`;
const kDisWh = `inv${inv}_batt_dischargeWh_today`;

const lastDay = flow.get(kDay);
let lastTs = flow.get(kTs);
let lastChargeW = flow.get(kChg);
let lastDischargeW = flow.get(kDis);

let chargeWh = flow.get(kChgWh);
let dischargeWh = flow.get(kDisWh);

if (!Number.isFinite(chargeWh)) chargeWh = 0;
if (!Number.isFinite(dischargeWh)) dischargeWh = 0;

// Reset si on change de jour
if (lastDay && lastDay !== dayKey) {
  chargeWh = 0;
  dischargeWh = 0;
}

// Puissances actuelles (W) - déjà positives chez toi
const curChargeW = Number.isFinite(state.battery_charge) ? state.battery_charge : 0;
const curDischargeW = Number.isFinite(state.battery_discharge) ? state.battery_discharge : 0;

const nowTs = Date.now();

if (Number.isFinite(lastTs) && Number.isFinite(lastChargeW) && Number.isFinite(lastDischargeW)) {
  const dtMs = nowTs - lastTs;
  // ignore si dt délirant (redémarrage / horloge) : > 10 minutes
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    chargeWh += ((lastChargeW + curChargeW) / 2) * dtH;
    dischargeWh += ((lastDischargeW + curDischargeW) / 2) * dtH;
  }
}

// Stocke contexte
flow.set(kDay, dayKey);
flow.set(kTs, nowTs);
flow.set(kChg, curChargeW);
flow.set(kDis, curDischargeW);
flow.set(kChgWh, chargeWh);
flow.set(kDisWh, dischargeWh);

// Expose dans state en kWh
state.battery_charge_day_kwh = Math.round((chargeWh / 1000) * 100) / 100;
state.battery_discharge_day_kwh = Math.round((dischargeWh / 1000) * 100) / 100;
state._day_key = dayKey; // debug optionnel

// ===== FILTRE ANTI-SPIKE (W) =====
const MAX_W = 15000;

function finiteNumber(x) {
  const nn = Number(x);
  return Number.isFinite(nn) ? nn : null;
}

function clampAbs(x, maxAbs) {
  if (x == null) return null;
  if (Math.abs(x) <= maxAbs) return x;
  return x < 0 ? -maxAbs : maxAbs;
}

// garde dernière valeur OK par inv + key
function sanitizeW(key, { maxAbs = MAX_W, allowNegative = true, forceNonNegative = false } = {}) {
  const v = finiteNumber(state[key]);
  if (v == null) return;

  // force >=0 si demandé
  let vv = v;
  if (forceNonNegative && vv < 0) vv = 0;

  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  // hors limite -> lastOk sinon clamp
  if (Math.abs(vv) > maxAbs) {
    if (lastOk != null && Number.isFinite(lastOk)) {
      state[key] = lastOk;
    } else {
      state[key] = clampAbs(vv, maxAbs);
    }
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, maxAbs });
    return;
  }

  // interdit négatif
  if (!allowNegative && vv < 0) {
    state[key] = (lastOk != null && Number.isFinite(lastOk)) ? lastOk : 0;
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, reason: "negative_not_allowed" });
    return;
  }

  // OK -> mémorise
  state[key] = vv;
  flow.set(lastKey, vv);
}

// Champs demandés
sanitizeW("ac_output_active_power", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("grid_power", { maxAbs: MAX_W, allowNegative: true });
sanitizeW("battery_charge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_discharge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_power", { maxAbs: MAX_W, allowNegative: true });

// ===== GRID TODAY (kWh) - from grid_power (W) =====
// Intégration trapèze + reset journalier selon timezone config
// On compte uniquement l'import (si grid_power négatif => 0)

const kGDay = `inv${inv}_grid_dayKey`;
const kGTs  = `inv${inv}_grid_lastTs`;
const kGLastW = `inv${inv}_grid_lastW`;
const kGWh = `inv${inv}_grid_Wh_today`;

let gLastDay = flow.get(kGDay);
let gLastTs = flow.get(kGTs);
let gLastW = flow.get(kGLastW);
let gWh = flow.get(kGWh);

if (!Number.isFinite(gWh)) gWh = 0;

// reset jour
if (gLastDay && gLastDay !== dayKey) {
  gWh = 0;
}

// puissance grid actuelle (import only)
const gCurW_raw = Number.isFinite(state.grid_power) ? state.grid_power : 0;
const gCurW = Math.max(0, gCurW_raw);

const gNowTs = Date.now();

if (Number.isFinite(gLastTs) && Number.isFinite(gLastW)) {
  const dtMs = gNowTs - gLastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    gWh += ((gLastW + gCurW) / 2) * dtH;
  }
}

flow.set(kGDay, dayKey);
flow.set(kGTs, gNowTs);
flow.set(kGLastW, gCurW);
flow.set(kGWh, gWh);

// expose en kWh (2 décimales)
state.grid_energy_day_kwh = Math.round((gWh / 1000) * 100) / 100;

context.set("state", state);
msg.inverterNum = inv;
msg.payload = state;
return msg;

// ===============================
// MQTT STATE PUBLISHER (STABLE JSON)
// Garantit une structure toujours identique
// ===============================

if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? 1;
const data = { ...msg.payload };

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const ensure = (obj, key, value = null) => {
    if (obj[key] === undefined) obj[key] = value;
};

// -------------------------------------------------
// 1) STRUCTURE PRINCIPALE
// -------------------------------------------------
ensure(data, "grid_voltage");
ensure(data, "grid_frequency");
ensure(data, "ac_output_voltage");
ensure(data, "ac_output_frequency");
ensure(data, "ac_output_active_power");
ensure(data, "output_load_percent");

ensure(data, "battery_voltage");
ensure(data, "battery_charging_current");
ensure(data, "battery_discharge_current");
ensure(data, "battery_capacity");

ensure(data, "battery_charge");
ensure(data, "battery_discharge");
ensure(data, "battery_power");

ensure(data, "pv_total_power");
ensure(data, "pv1_power");
ensure(data, "pv2_power");

ensure(data, "pv1_input_voltage");
ensure(data, "pv2_input_voltage");
ensure(data, "pv1_input_current");
ensure(data, "pv2_input_current");

ensure(data, "grid_power");
ensure(data, "inverter_heat_sink_temp");

ensure(data, "operation_mode");

// -------------------------------------------------
// 2) ENERGIES (souvent absentes selon timing)
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag) data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");
ensure(data.diag, "fault_state", "unknown");
ensure(data.diag, "fault_details", "unknown");
ensure(data.diag, "warn_state", "unknown");
ensure(data.diag, "warn_details", "unknown");

// -------------------------------------------------
// 4) PARAMS (CRITIQUE POUR SELECT/NUMBER)
// -------------------------------------------------
if (!data.params) data.params = {};
if (!data.params.qpiri) data.params.qpiri = {};
if (!data.params.qdop) data.params.qdop = {};

// valeurs null si pas encore connues (HA ne plantera plus)
const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "output_source_priority");
ensure(qpiri, "charger_source_priority");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

ensure(qpiri, "max_ac_charging_current");
ensure(qpiri, "max_charging_current");
ensure(qpiri, "max_discharging_current");

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");

// -------------------------------------------------
// 5) PUBLISH MQTT
// -------------------------------------------------
return [
    {
        topic: `voltronic/${inv}/state`,
        payload: JSON.stringify(data),
        retain: true
    },
    {
        topic: `voltronic/${inv}/availability`,
        payload: "online",
        retain: true
    }
];

const inv = msg.inverterNum ?? 1;
const key = `inv${inv}_queue`;

let q = flow.get(key);
if (!Array.isArray(q)) q = [];

// msg peut être 1 commande, ou un lot (si tu envoies [msgs])
// Ici, on gère les deux cas proprement.
const toPush = [];

if (Array.isArray(msg)) {
    // rare : si tu envoies direct un tableau de msgs
    toPush.push(...msg);
} else if (Array.isArray(msg.payload) && msg.payload?.[0]?.command) {
    // si jamais ton flow passe un tableau dans payload
    toPush.push(...msg.payload);
} else {
    // msg normal
    toPush.push(msg);
}

// ajoute uniquement si on a une commande
toPush.forEach(m => {
    const cmd = (m.command || m._cmd || m.payload || "").toString().trim().toUpperCase();
    if (!cmd) return;

    q.push({
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        payload: cmd,
        enqueued_ts: Date.now()
    });
});

// limite taille
if (q.length > 200) q = q.slice(-200);

flow.set(key, q);

// déclenche le pump
return { inverterNum: inv, topic: "pump" };

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let inFlight = flow.get(inFlightKey);

// Si une commande est déjà en attente de réponse, on n’en envoie pas une autre
if (inFlight && (Date.now() - (inFlight.ts || 0)) < 3000) {
  return null;
}

let q = flow.get(qKey);
if (!Array.isArray(q) || q.length === 0) return null;

// Prend la prochaine commande
const next = q.shift();
flow.set(qKey, q);

// Marque comme en vol
flow.set(inFlightKey, { cmd: next.command, ts: Date.now() });

// Envoie au construire commande
return next;

// HA SET -> Voltronic CMD  (1 sortie)
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = (msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);   // ID logique / port RS232 (1..3)
const param = m[2];

// --------------------
// Normalisation payload (fix: guillemets / "200"" / "\"200\"" etc.)
// --------------------
let v = msg.payload;

if (typeof v === "string") {
  v = v.trim();

  // retire guillemets parasites au début/fin
  // ex: '"200"' -> 200 ; '200""' -> 200 ; '"Solar first"' -> Solar first
  v = v.replace(/^"+|"+$/g, "");

  // si c'est encore un JSON string (rare), tente parse
  // ex: "\"200\"" (valeur stringifiée)
  try {
    if (v.startsWith('\\"') || (v.startsWith('"') && v.endsWith('"'))) {
      v = JSON.parse(v);
    }
  } catch (e) {
    // ignore
  }

  if (typeof v === "string") {
    v = v.trim().replace(/^"+|"+$/g, "");
  }
}

// --------------------
// helpers
// --------------------
// robuste: extrait le 1er nombre si string contient des caractères
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = x.trim().replace(/^"+|"+$/g, "");
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");
const fixed1 = (x) => Number(x).toFixed(1);
const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));

// --------------------
// parallel "machine id" (Voltronic parallel ID) != inverterNum (RS232 port)
// --------------------
let machine = flow.get(`inv${inverterNum}_parallel_id`);
if (machine === undefined || machine === null || machine === "") machine = 0;
machine = Number(machine);
if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;

let cmd = null;

// =====================
// SELECTS
// =====================
if (param === "output_source_priority") {
  const map = { UtilitySolarBat: "POP00", SolarUtilityBat: "POP01", SolarBatUtility: "POP02" };
  cmd = map[String(v)] || null;

} else if (param === "charger_source_priority") {
  const map = { "Solar first": "PCP01", "Solar + Utility": "PCP02", "Only solar": "PCP03" };
  cmd = map[String(v)] || null;

} else if (param === "battery_type") {
  const map = {
    AGM: "PBT00",
    Flooded: "PBT01",
    User: "PBT02",
    Pylon: "PBT03",
    Weco: "PBT05",
    Soltaro: "PBT06",
    Lib: "PBT08",
    Lic: "PBT09"
  };
  cmd = map[String(v)] || null;
}

// =====================
// VOLTAGES nn.n
// =====================
else if (param === "battery_recharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCV${fixed1(nv)}`;

} else if (param === "battery_re_discharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDV${fixed1(nv)}`;

} else if (param === "battery_under_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDV${fixed1(nv)}`;

} else if (param === "battery_bulk_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PCVV${fixed1(nv)}`;

} else if (param === "battery_float_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBFT${fixed1(nv)}`;
}

// =====================
// CURRENTS (0..200)
// =====================
else if (param === "max_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MNCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MNCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_ac_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MUCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MUCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_discharging_current") {
  // PBATMAXDISC<nnn>
  // - 000 = disable (doc)
  // - sinon 001..200 (ton discovery)
  // Si tu utilises "0" = Unsupported côté HA, ne rien envoyer.
  const sv = String(v).trim().replace(/^"+|"+$/g, "");

  // 0 utilisé comme "Unsupported" ? => ignore
  // (si au contraire tu veux "disable", commente ce bloc)
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  // Ici: 1..200
  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
}

// =====================
// QDOP thresholds %
// =====================
else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
}

if (!cmd) return null;

// --------------------
// message builder
// --------------------
const mk = (c) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true
});

// 1) SET message (priority)
const setMsg = mk(cmd);
setMsg._burst = false;

// 2) Refresh burst after SET
const refresh = ["QPIRI", "QDI", "QFLAG", "QDOP", "QMOD", "QPIGS"];
// optional if supported: refresh.splice(refresh.indexOf("QPIGS")+1, 0, "QPIGS2");

const out = [setMsg, ...refresh.map(mk)];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${out.length - 1}`
});

// 1 output => array of messages in output 1
return [out];

// HA SET -> Voltronic CMD  (1 sortie)
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = (msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);   // ID logique / port RS232 (1..3)
const param = m[2];

// --------------------
// Normalisation payload (fix: guillemets / "200"" / "\"200\"" etc.)
// --------------------
let v = msg.payload;

if (typeof v === "string") {
  v = v.trim();

  // retire guillemets parasites au début/fin
  // ex: '"200"' -> 200 ; '200""' -> 200 ; '"Solar first"' -> Solar first
  v = v.replace(/^"+|"+$/g, "");

  // si c'est encore un JSON string (rare), tente parse
  // ex: "\"200\"" (valeur stringifiée)
  try {
    if (v.startsWith('\\"') || (v.startsWith('"') && v.endsWith('"'))) {
      v = JSON.parse(v);
    }
  } catch (e) {
    // ignore
  }

  if (typeof v === "string") {
    v = v.trim().replace(/^"+|"+$/g, "");
  }
}

// --------------------
// helpers
// --------------------
// robuste: extrait le 1er nombre si string contient des caractères
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = x.trim().replace(/^"+|"+$/g, "");
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");
const fixed1 = (x) => Number(x).toFixed(1);
const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));

// --------------------
// parallel "machine id" (Voltronic parallel ID) != inverterNum (RS232 port)
// --------------------
let machine = flow.get(`inv${inverterNum}_parallel_id`);
if (machine === undefined || machine === null || machine === "") machine = 0;
machine = Number(machine);
if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;

let cmd = null;

// =====================
// SELECTS
// =====================
if (param === "output_source_priority") {
  const map = { UtilitySolarBat: "POP00", SolarUtilityBat: "POP01", SolarBatUtility: "POP02" };
  cmd = map[String(v)] || null;

} else if (param === "charger_source_priority") {
  const map = { "Solar first": "PCP01", "Solar + Utility": "PCP02", "Only solar": "PCP03" };
  cmd = map[String(v)] || null;

} else if (param === "battery_type") {
  const map = {
    AGM: "PBT00",
    Flooded: "PBT01",
    User: "PBT02",
    Pylon: "PBT03",
    Weco: "PBT05",
    Soltaro: "PBT06",
    Lib: "PBT08",
    Lic: "PBT09"
  };
  cmd = map[String(v)] || null;
}

// =====================
// VOLTAGES nn.n
// =====================
else if (param === "battery_recharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCV${fixed1(nv)}`;

} else if (param === "battery_re_discharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDV${fixed1(nv)}`;

} else if (param === "battery_under_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDV${fixed1(nv)}`;

} else if (param === "battery_bulk_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PCVV${fixed1(nv)}`;

} else if (param === "battery_float_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBFT${fixed1(nv)}`;
}

// =====================
// CURRENTS (0..200)
// =====================
else if (param === "max_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MNCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MNCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_ac_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MUCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MUCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_discharging_current") {
  // PBATMAXDISC<nnn>
  // - 000 = disable (doc)
  // - sinon 001..200 (ton discovery)
  // Si tu utilises "0" = Unsupported côté HA, ne rien envoyer.
  const sv = String(v).trim().replace(/^"+|"+$/g, "");

  // 0 utilisé comme "Unsupported" ? => ignore
  // (si au contraire tu veux "disable", commente ce bloc)
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  // Ici: 1..200
  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
}

// =====================
// QDOP thresholds %
// =====================
else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
}

if (!cmd) return null;

// --------------------
// message builder
// --------------------
const mk = (c) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true
});

// 1) SET message (priority)
const setMsg = mk(cmd);
setMsg._burst = false;

// 2) Refresh burst after SET
const refresh = ["QPIRI", "QDI", "QFLAG", "QDOP", "QMOD", "QPIGS"];
// optional if supported: refresh.splice(refresh.indexOf("QPIGS")+1, 0, "QPIGS2");

const out = [setMsg, ...refresh.map(mk)];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${out.length - 1}`
});

// 1 output => array of messages in output 1
return [out];

// ====== CONSTRUIRE COMMANDE (Voltronic) ======
const helpers = global.get("helpers");

if (!helpers || typeof helpers.buildVoltronicCommand !== "function") {
  node.error("helpers.buildVoltronicCommand introuvable (global.helpers)");
  return null;
}

// Récupère la commande (priorité à msg.command)
let cmd = (msg.command ?? msg._cmd ?? msg.payload ?? "")
  .toString()
  .trim();

// ------------------------------
// FIX: commandes qui arrivent avec guillemets
// ex: '"PBATMAXDISC150"' ou 'PBATMAXDISC150""'
// ------------------------------

// si c'est du JSON stringifié (ex: "\"PBATMAXDISC150\""), tente parse
try {
  if (cmd.startsWith('"') || cmd.startsWith('\\"')) {
    const parsed = JSON.parse(cmd);
    if (typeof parsed === "string") cmd = parsed;
  }
} catch (e) {
  // ignore
}

// retire guillemets parasites au début/fin
cmd = cmd.trim().replace(/^"+|"+$/g, "");

// upper après nettoyage
cmd = cmd.toUpperCase();

if (!cmd) {
  node.warn("Commande vide -> ignorée");
  return null;
}

/*
  Validation "safe" :
  - Requêtes classiques: QPIGS, QPIRI, QMOD, QET, QLD20260220, etc.
  - SET Voltronic: souvent Pxxxx + valeur (ex: PCVV55.7, PBT02, PBATMAXDISC150, etc.)
  On autorise uniquement: A-Z / 0-9 / '.' / '-' et on contrôle les patterns.
*/
const isQueryOrStat =
  /^[A-Z]{2,6}[0-9]*$/.test(cmd); // ex: QPIGS, QPIRI, QET, QED20260220, QEY2026...

const isSetWithValue =
  /^P[A-Z0-9]{2,12}-?[0-9]+(\.[0-9]+)?$/.test(cmd);
// ↑ élargi à 2..12 (PBATMAXDISC = 10 lettres après P)

// IMPORTANT: PBATMAXDISC est un SET spécial avec 3 digits, ex: PBATMAXDISC150
// Il match déjà la regex ci-dessus, mais on garde ce commentaire pour clarté.

if (!isQueryOrStat && !isSetWithValue) {
  node.warn(`Commande invalide ignorée: "${cmd}"`);
  return null;
}

// Conserver la commande envoyée (utile pour associer RX)
msg.command = cmd;
msg._cmd = cmd;

// Construire la trame (CRC + CR)
let buf;
try {
  buf = helpers.buildVoltronicCommand(cmd);
} catch (e) {
  node.error(`Erreur buildVoltronicCommand("${cmd}") : ${e.message || e}`);
  return null;
}

// Payload = Buffer à envoyer dans Serial Out
msg.payload = buf;

// Debug utile
msg._tx_ts = Date.now();
msg._tx_ascii = cmd;
msg._tx_hex = buf.toString("hex");

// Status (optionnel)
node.status({
  fill: "blue",
  shape: "dot",
  text: `${cmd} → ond${msg.inverterNum ?? "?"}`
});

// Mémorise la dernière commande par onduleur (utile RX/timeout)
if (msg.inverterNum != null) {
  flow.set(`inv${msg.inverterNum}_last_cmd`, msg._cmd);
  flow.set(`inv${msg.inverterNum}_last_cmd_ts`, Date.now());
}

return msg;

// ====== REQUETES (Option A + firstRun + force + QPIGS2 auto-disable + retry 1h + DIAG) ======
// ✅ Fix: QPIRI/QDOP + DIAG/FW bien envoyés AU BOOT
// ✅ Fix: Burst boot exécuté AVANT le tick realtime (évite “perte” si queue/pump limité)
// ✅ Garde ta logique QPIGS2 auto-disable + retry 1h

const inverterNum = 3;
const ts = Date.now();
const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());

const yyyymm = `${yyyy}${mm}`;
const yyyymmdd = `${yyyy}${mm}${dd}`;

// état alternance
let alt = context.get("alt");
if (alt === undefined || alt === null) alt = 0;

// firstRun peut rester false si context persistant
let firstRun = context.get("firstRun");
if (firstRun === undefined) firstRun = true;

// Permet de forcer un burst via un inject bouton (msg.forceFirstRun=true)
if (msg && msg.forceFirstRun === true) {
  firstRun = true;
}

// timers existants
let nextQMOD = context.get("nextQMOD");
let nextHour = context.get("nextHour");
let nextDay10m = context.get("nextDay10m");
let nextMonth6 = context.get("nextMonth6");
let nextYear24 = context.get("nextYear24");

// timers params
let nextQPIRI = context.get("nextQPIRI");
let nextQDOP = context.get("nextQDOP");

// retry QPIGS2 même si désactivé
let nextRetryQPIGS2 = context.get("nextRetryQPIGS2");
if (!nextRetryQPIGS2) nextRetryQPIGS2 = ts + 60 * 60 * 1000;

// ✅ DIAG timers
let diagDone = context.get("diagDone");           // 1-shot after boot (flag)
let nextQPIWS = context.get("nextQPIWS");         // 5 min

function makeCmd(cmd) {
  return { inverterNum, command: cmd, _cmd: cmd, payload: cmd };
}

const msgs = [];

// ----- QPIGS/QPIGS2 stratégie -----
const supportsQPIGS2 = flow.get(`inv${inverterNum}_supports_qpigs2`);
const useQPIGS2 = (supportsQPIGS2 !== false);

function pushRealtimeTick() {
  if (useQPIGS2) {
    msgs.push(makeCmd(alt === 0 ? "QPIGS" : "QPIGS2"));
    alt = alt ? 0 : 1;
  } else {
    msgs.push(makeCmd("QPIGS"));
    if (ts >= nextRetryQPIGS2) {
      msgs.push(makeCmd("QPIGS2"));
      nextRetryQPIGS2 = ts + 60 * 60 * 1000;
    }
  }
}

// =========================
// 1) BOOT BURST (firstRun)
// =========================
if (firstRun) {
  const burst = [
    // ✅ PARAMS AU BOOT (sinon tu attends 5 minutes)
    "QPIRI",
    "QDOP",

    // realtime info utile
    "QMOD",

    // energies
    "QET", `QEY${yyyy}`, `QEM${yyyymm}`, `QED${yyyymmdd}`,
    "QLT", `QLY${yyyy}`, `QLM${yyyymm}`, `QLD${yyyymmdd}`,

    // ✅ DIAG au boot
    "QMN",      // model
    "QID",      // serial (si besoin: remplacer par QSID)
    "QVFW",     // fw main
    "QVFW3",    // fw remote/panel (si supporté)
    "QPIWS"     // warnings/faults (1er état)
  ];

  burst.forEach(c => msgs.push(makeCmd(c)));

  // Schedules
  nextQMOD = ts + 5 * 60 * 1000;
  nextHour = ts + 60 * 60 * 1000;
  nextDay10m = ts + 10 * 60 * 1000;
  nextMonth6 = ts + 6 * 60 * 60 * 1000;
  nextYear24 = ts + 24 * 60 * 60 * 1000;

  // ✅ Tu viens de les envoyer -> replanifie à +5 minutes
  nextQPIRI = ts + 5 * 60 * 1000;
  nextQDOP = ts + 5 * 60 * 1000;

  // ✅ DIAG flags/timers
  diagDone = true;
  nextQPIWS = ts + 5 * 60 * 1000;

  firstRun = false;

  node.status({ fill: "green", shape: "dot", text: `FIRST RUN: ${msgs.length} cmds` });
}

// =========================
// 2) NORMAL MODE (timers)
// =========================
else {
  // QMOD 5 min
  if (nextQMOD == null) nextQMOD = ts + 5 * 60 * 1000;
  if (ts >= nextQMOD) {
    msgs.push(makeCmd("QMOD"));
    nextQMOD = ts + 5 * 60 * 1000;
  }

  // QPIRI 5 min
  if (nextQPIRI == null) nextQPIRI = ts + 5 * 60 * 1000;
  if (ts >= nextQPIRI) {
    msgs.push(makeCmd("QPIRI"));
    nextQPIRI = ts + 5 * 60 * 1000;
  }

  // QDOP 5 min
  if (nextQDOP == null) nextQDOP = ts + 5 * 60 * 1000;
  if (ts >= nextQDOP) {
    msgs.push(makeCmd("QDOP"));
    nextQDOP = ts + 5 * 60 * 1000;
  }

  // ✅ QPIWS (fault/warnings) 5 min
  if (nextQPIWS == null) nextQPIWS = ts + 5 * 60 * 1000;
  if (ts >= nextQPIWS) {
    msgs.push(makeCmd("QPIWS"));
    nextQPIWS = ts + 5 * 60 * 1000;
  }

  // Hourly
  if (nextHour == null) nextHour = ts + 60 * 60 * 1000;
  if (ts >= nextHour) {
    // énergies (total)
    msgs.push(makeCmd("QET"));
    msgs.push(makeCmd("QLT"));

    // diagnostics (1 fois/heure)
    msgs.push(makeCmd("QMN"));
    msgs.push(makeCmd("QID"));
    msgs.push(makeCmd("QVFW"));
    msgs.push(makeCmd("QVFW3"));

    nextHour = ts + 60 * 60 * 1000;
  }

  // Daily 10min
  if (nextDay10m == null) nextDay10m = ts + 10 * 60 * 1000;
  if (ts >= nextDay10m) {
    msgs.push(makeCmd(`QED${yyyymmdd}`));
    msgs.push(makeCmd(`QLD${yyyymmdd}`));
    nextDay10m = ts + 10 * 60 * 1000;
  }

  // Monthly 6h
  if (nextMonth6 == null) nextMonth6 = ts + 6 * 60 * 60 * 1000;
  if (ts >= nextMonth6) {
    msgs.push(makeCmd(`QEM${yyyymm}`));
    msgs.push(makeCmd(`QLM${yyyymm}`));
    nextMonth6 = ts + 6 * 60 * 60 * 1000;
  }

  // Yearly 24h
  if (nextYear24 == null) nextYear24 = ts + 24 * 60 * 60 * 1000;
  if (ts >= nextYear24) {
    msgs.push(makeCmd(`QEY${yyyy}`));
    msgs.push(makeCmd(`QLY${yyyy}`));
    nextYear24 = ts + 24 * 60 * 60 * 1000;
  }
}

// =========================
// 3) REALTIME TICK (toujours à la fin)
// =========================
pushRealtimeTick();

// =========================
// save context
// =========================
context.set("alt", alt);
context.set("firstRun", firstRun);
context.set("nextQMOD", nextQMOD);
context.set("nextHour", nextHour);
context.set("nextDay10m", nextDay10m);
context.set("nextMonth6", nextMonth6);
context.set("nextYear24", nextYear24);
context.set("nextQPIRI", nextQPIRI);
context.set("nextQDOP", nextQDOP);
context.set("nextRetryQPIGS2", nextRetryQPIGS2);

// ✅ save DIAG
context.set("diagDone", diagDone);
context.set("nextQPIWS", nextQPIWS);

return [msgs];

// ====== PARSER 1 (Voltronic) - QUEUE MODE ======
// Entrée: msg.payload = Buffer (Serial IN en "a single buffer", pas de split)
// Sorties:
//   1) trigger pump (msg.topic="pump")
//   2) data parsée (vers normalize state)
// Associe la réponse à la commande "inflight" (envoyée par Queue Pump)

const inv = msg.inverterNum ?? 1;
if (!Buffer.isBuffer(msg.payload)) return null;

// --- accumulateur RX ---
let rx = context.get("rxbuf");
if (!Buffer.isBuffer(rx)) rx = Buffer.alloc(0);

// sécurité overflow
if (rx.length > 8192) rx = Buffer.alloc(0);

// concat
rx = Buffer.concat([rx, msg.payload]);

const CR = 0x0D;

// extrait toutes les frames finissant par CR
const frames = [];
while (true) {
  const idx = rx.indexOf(CR);
  if (idx === -1) break;
  frames.push(rx.slice(0, idx + 1));
  rx = rx.slice(idx + 1);
}
context.set("rxbuf", rx);

if (!frames.length) return null;

// commande inflight (celle réellement envoyée)
const inflightKey = `inv${inv}_inflight`;
const inflight = flow.get(inflightKey);
const inflightCmd = inflight?.cmd || "UNKNOWN";

// Nettoyage trame -> ASCII sans CRC/CR
function cleanAsciiFromFrame(frameBuf) {
  // NAK brut possible (0x15)
  if (frameBuf.length === 1 && frameBuf[0] === 0x15) return "NAK";

  // Normalement: <data ASCII> + <CRC 2 bytes> + <CR>
  let dataBuf = frameBuf;

  if (frameBuf.length >= 3 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -3); // retire CRC(2) + CR(1)
  } else if (frameBuf.length >= 1 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -1); // fallback retire CR
  }

  return dataBuf.toString("ascii");
}

function parseFrame(frameBuf, cmd) {
  const ascii = cleanAsciiFromFrame(frameBuf);

  // Détection NAK "NAK" ou 0x15
  if (ascii.includes("NAK") || ascii === "NAK") {
    return {
      inverter: inv,
      command: cmd,
      nak: true,
      raw: "NAK",
      fields: [],
      nums: [],
      value: null
    };
  }

  // Enlever parenthèses si présentes
  let body = ascii.trim();
  if (body.startsWith("(")) body = body.slice(1);
  if (body.endsWith(")")) body = body.slice(0, -1);
  body = body.trim();

  const fields = body.length ? body.split(/\s+/) : [];
  const nums = fields.map(v => {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  });

  // Cas énergie (1 valeur)
  const isEnergyCmd = /^Q(E[TYMD]|L[TYMD])/.test(cmd);
  let value = null;
  if (isEnergyCmd && fields.length >= 1) {
    const n0 = Number(fields[0]);
    if (Number.isFinite(n0)) value = n0;
  }

  return {
    inverter: inv,
    command: cmd,
    raw: body,
    fields,
    nums,
    value
  };
}

// Ici, on part du principe QUEUE = 1 commande envoyée -> 1 réponse attendue.
// Mais on gère quand même le cas "plusieurs frames d'un coup" :
// - 1ère frame = inflightCmd
// - frames suivantes = UNKNOWN (ou on garde inflightCmd si tu préfères)
const outMsgs = [];
for (let i = 0; i < frames.length; i++) {
  const cmd = (i === 0) ? inflightCmd : "UNKNOWN";
  outMsgs.push({
    inverterNum: inv,
    _cmd: cmd,
    command: cmd,
    payload: parseFrame(frames[i], cmd),
    _rx_ts: Date.now()
  });
}

// ACK : dès qu'on reçoit au moins une frame, on libère inflight
flow.set(inflightKey, null);

// Trigger pump immédiatement (pour envoyer la prochaine commande)
const pumpMsg = { inverterNum: inv, topic: "pump" };

// Sortie 1: pump trigger
// Sortie 2: data parsée (plusieurs messages possibles)
return [[pumpMsg], outMsgs];

// ====== NORMALIZE STATE (AUTO / MULTI-MODEL) - + TZ dynamic + GRID TODAY ======
if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? msg.payload.inverter ?? 1;

// Normaliser la commande (évite "QPIRI\r", "qpiri", "QPIRI ")
const cmd = String(msg.payload.command || msg.command || msg._cmd || "UNKNOWN")
  .trim()
  .toUpperCase();

const f = Array.isArray(msg.payload.fields) ? msg.payload.fields : [];
const n = Array.isArray(msg.payload.nums) ? msg.payload.nums : [];
const value = msg.payload.value;

let state = context.get("state");
if (!state || typeof state !== "object") state = {};

// helpers
const num = (idx) => (Number.isFinite(n[idx]) ? n[idx] : null);
const int = (idx) => {
  const v = num(idx);
  return v == null ? null : Math.trunc(v);
};
const round = (v, d) => {
  const nn = Number(v);
  if (!Number.isFinite(nn)) return null;
  const m = 10 ** d;
  return Math.round(nn * m) / m;
};

// --- apprentissage index pv1_power par node (donc par inverter) ---
let pv1PowerIdx = context.get("pv1PowerIdx"); // mémorisé par node

// ===== QPIGS =====
if (cmd === "QPIGS" && f.length >= 16) {
  // Champs communs (stables)
  if (f.length > 0) state.grid_voltage = round(num(0), 1);
  if (f.length > 1) state.grid_frequency = round(num(1), 1);
  if (f.length > 2) state.ac_output_voltage = round(num(2), 1);
  if (f.length > 3) state.ac_output_frequency = round(num(3), 1);

  // Apparent/active/load : souvent 4/5/6
  if (f.length > 4) state.ac_output_apparent_power = int(4);
  if (f.length > 5) state.ac_output_active_power = int(5);
  if (f.length > 6) state.output_load_percent = int(6);

  // bus voltage : souvent 7
  if (f.length > 7) state.bus_voltage = int(7);

  // ✅ Batterie : tension 2 décimales, courants 1 décimale
  if (f.length > 8) state.battery_voltage = round(num(8), 2);
  if (f.length > 9) state.battery_charging_current = round(num(9), 1);
  if (f.length > 10) state.battery_capacity = int(10);
  if (f.length > 11) state.inverter_heat_sink_temp = int(11);

  // PV entrée : souvent 12/13
  if (f.length > 12) state.pv1_input_current = round(num(12), 1);
  if (f.length > 13) state.pv1_input_voltage = round(num(13), 1);

  // Battery voltage from SCC
  if (f.length > 14) state.battery_voltage_from_scc = round(num(14), 2);

  // Discharge current
  if (f.length > 15) state.battery_discharge_current = round(num(15), 1);

  // ⭐ GLOBAL CURRENT
  const IchgA = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
  const IdisA = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;
  state.global_current = round(IchgA - IdisA, 1);

  // ===== INVERTER OUTPUT CURRENT (A) - calculated =====
  // Approximation: I = P / V (ignores PF). Useful as an indicator.
  const Vac = Number.isFinite(state.ac_output_voltage) ? state.ac_output_voltage : null;
  const Pac = Number.isFinite(state.ac_output_active_power) ? state.ac_output_active_power : null;
  if (Vac != null && Vac > 1 && Pac != null) {
    state.inverter_output_current = Math.round((Pac / Vac) * 10) / 10; // 0.1A
  } else {
    state.inverter_output_current = null;
  }

  // ---- PV1 Power : auto
  if (pv1PowerIdx != null && f.length > pv1PowerIdx) {
    state.pv1_power = int(pv1PowerIdx);
  } else {
    const candidates = [19, 20, 18, 17, 16]; // variantes connues
    for (const idx of candidates) {
      if (f.length > idx && Number.isFinite(n[idx])) {
        const I = state.pv1_input_current;
        const V = state.pv1_input_voltage;
        const pCalc = (Number.isFinite(I) && Number.isFinite(V)) ? (I * V) : null;
        const pField = n[idx];

        if (pCalc != null && pCalc > 10) {
          const ratio = pField / pCalc;
          if (ratio > 0.8 && ratio < 1.2) {
            pv1PowerIdx = idx;
            context.set("pv1PowerIdx", pv1PowerIdx);
            state.pv1_power = int(idx);
            break;
          }
        } else {
          if (idx === 19) {
            state.pv1_power = int(19);
            break;
          }
        }
      }
    }
  }

  // ===== GRID POWER (champ 25 firmwares récents) =====
  // n[24] car index 0-based => "champ 25"
  if (f.length > 24 && Number.isFinite(n[24])) {
    state.grid_power = int(24);
  }

  state._last_qpigs_ts = Date.now();
}

// ===== QPIGS2 (optionnel) =====
if (cmd === "QPIGS2" && f.length >= 3) {
  state.pv2_input_current = round(num(0), 1);
  state.pv2_input_voltage = round(num(1), 1);
  state.pv2_power = int(2);
  state._last_qpigs2_ts = Date.now();
}

// ===== QMOD =====
if (cmd === "QMOD") {
  const rawMode = (f[0] ?? msg.payload.raw ?? "").toString().trim();
  const modeMap = { P: "Power On", S: "Standby", L: "Grid", B: "Battery", F: "Fault" };
  state.operation_mode = modeMap[rawMode] || rawMode || null;
  state.operation_mode_code = rawMode || null;
  state._last_qmod_ts = Date.now();
}

// ===== QPIRI -> PARAMETRES =====
if (cmd === "QPIRI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  const mapBatteryType = (code) => {
    const m = { 0: "AGM", 1: "Flooded", 2: "User", 3: "Pylon", 5: "Weco", 6: "Soltaro", 8: "Lib", 9: "Lic" };
    return m[code] ?? String(code ?? "");
  };
  const mapOutputPriority = (code) => {
    const m = { 0: "UtilitySolarBat", 1: "SolarUtilityBat", 2: "SolarBatUtility" };
    return m[code] ?? String(code ?? "");
  };
  const mapChargerPriority = (code) => {
    const m = { 1: "Solar first", 2: "Solar + Utility", 3: "Only solar" };
    return m[code] ?? String(code ?? "");
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  const battTypeCode = nf(12);
  const outPrioCode = nf(16);
  const chgPrioCode = nf(17);

  state.params.qpiri = {
    battery_recharge_voltage: nf(8),
    battery_under_voltage: nf(9),
    battery_bulk_voltage: nf(10),
    battery_float_voltage: nf(11),

    battery_type_code: battTypeCode,
    battery_type: mapBatteryType(battTypeCode),

    max_ac_charging_current: nf(13),
    max_charging_current: nf(14),

    output_source_priority_code: outPrioCode,
    output_source_priority: mapOutputPriority(outPrioCode),

    charger_source_priority_code: chgPrioCode,
    charger_source_priority: mapChargerPriority(chgPrioCode),

    battery_re_discharge_voltage: nf(22),
    max_discharging_current: nf(27),

    ts: Date.now()
  };

  state._last_qpiri_ts = Date.now();
}

// ===== QDOP -> PARAMETRES batterie (%) =====
if (cmd === "QDOP" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  state.params.qdop = {
    battery_recharge_capacity_pct: nf(8),
    battery_redischarge_capacity_pct: nf(9),
    battery_under_capacity_pct: nf(10),
    ts: Date.now()
  };

  state._last_qdop_ts = Date.now();
}

// ===== DIAGNOSTIC (model/serial/fw + faults/warnings) =====
if (cmd === "QMN" && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.model = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qmn_ts = Date.now();
}

if ((cmd === "QID" || cmd === "QSID") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.serial = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qid_ts = Date.now();
}

if ((cmd === "QVFW" || cmd === "QVFW3") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  const fw = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  if (cmd === "QVFW") state.diag.fw_main = fw;
  if (cmd === "QVFW3") state.diag.fw_remote = fw;
  state._last_qvfw_ts = Date.now();
}

// ===== QPIWS -> FAULTS / WARNINGS (4 lignes HA) =====
if (cmd === "QPIWS" && msg.payload?.nak !== true) {
  const bits = String(f[0] ?? msg.payload.raw ?? "").trim();
  if (!state.diag || typeof state.diag !== "object") state.diag = {};

  const bit = (i) => (bits.length > i ? bits.charAt(i) === "1" : false);
  const a1_fault = bit(1);

  const map = [
    { i: 0, label: "PV loss", kind: "warn" },
    { i: 1, label: "Inverter fault", kind: "fault" },
    { i: 2, label: "Bus over", kind: "fault" },
    { i: 3, label: "Bus under", kind: "fault" },
    { i: 4, label: "Bus soft fail", kind: "fault" },
    { i: 5, label: "Line fail", kind: "warn" },
    { i: 6, label: "OPV short", kind: "fault" },
    { i: 7, label: "Inverter voltage low", kind: "fault" },
    { i: 8, label: "Inverter voltage high", kind: "fault" },
    { i: 9, label: "Over temperature", kind: () => a1_fault ? "fault" : "warn" },
    { i: 10, label: "Fan locked", kind: () => a1_fault ? "fault" : "warn" },
    { i: 11, label: "Battery voltage high", kind: () => a1_fault ? "fault" : "warn" },
    { i: 12, label: "Battery low alarm", kind: "warn" },
    { i: 14, label: "Battery shutdown", kind: "warn" },
    { i: 15, label: "Battery derating", kind: "warn" },
    { i: 16, label: "Over load", kind: () => a1_fault ? "fault" : "warn" },
    { i: 17, label: "EEPROM fault", kind: "warn" },
    { i: 18, label: "Inverter over current", kind: "fault" },
    { i: 19, label: "Inverter soft fail", kind: "fault" },
    { i: 20, label: "Self test fail", kind: "fault" },
    { i: 21, label: "OP DC voltage over", kind: "fault" },
    { i: 23, label: "Current sensor fail", kind: "fault" },
    { i: 33, label: "Low PV energy", kind: "warn" },
    { i: 34, label: "High AC input", kind: "warn" },
    { i: 35, label: "Battery equalization", kind: "warn" }
  ];

  const faults = [];
  const warns = [];

  for (const m of map) {
    if (!bit(m.i)) continue;
    const k = (typeof m.kind === "function") ? m.kind() : m.kind;
    if (k === "fault") faults.push(m.label);
    else warns.push(m.label);
  }

  state.diag.fault_state = faults.length ? "FAULT" : "OK";
  state.diag.fault_details = faults.length ? faults.join(", ") : "None";
  state.diag.warn_state = warns.length ? "WARN" : "OK";
  state.diag.warn_details = warns.length ? warns.join(", ") : "None";
  state.diag.has_fault = faults.length > 0;
  state.diag.has_warning = warns.length > 0;
  state.diag._last_qpiws_ts = Date.now();
}

// ===== Support QPIGS2 (diagnostic) =====
const supportsKey = `inv${inv}_supports_qpigs2`;
const supports = flow.get(supportsKey);
if (supports !== undefined) state.supports_qpigs2 = (supports !== false);

// ===== ENERGIES (FIX Today) =====
const round2 = (v) => (v == null ? null : Math.round(v * 100) / 100);
const toKwhToday = (v) => (!Number.isFinite(v) ? null : round2(v / 1000));
const toKwhAuto = (v) => (!Number.isFinite(v) ? null : (v >= 10000 ? round2(v / 1000) : round2(v)));

if (Number.isFinite(value)) {
  // PV
  if (cmd === "QET") { state.pv_energy_total_raw = value; state.pv_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEY")) { state.pv_energy_year_raw = value; state.pv_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEM")) { state.pv_energy_month_raw = value; state.pv_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QED")) { state.pv_energy_day_raw = value; state.pv_energy_day_kwh = toKwhToday(value); }

  // LOAD
  if (cmd === "QLT") { state.load_energy_total_raw = value; state.load_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLY")) { state.load_energy_year_raw = value; state.load_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLM")) { state.load_energy_month_raw = value; state.load_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLD")) { state.load_energy_day_raw = value; state.load_energy_day_kwh = toKwhToday(value); }

  state._last_energy_ts = Date.now();
}

// ===== PV total power =====
const pv1 = Number.isFinite(state.pv1_power) ? state.pv1_power : 0;
const pv2 = Number.isFinite(state.pv2_power) ? state.pv2_power : 0;
state.pv_total_power = pv1 + pv2;

// ===== BATTERY POWER (W) - CUSTOM SENSORS =====
const Vb = Number.isFinite(state.battery_voltage) ? state.battery_voltage : null;
const Ichg = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
const Idis = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;

if (Vb != null) {
  const chargeW = round(Vb * Math.max(0, Ichg), 1);
  const dischargeW = round(Vb * Math.max(0, Idis), 1);

  state.battery_charge = chargeW;              // +W
  state.battery_discharge = dischargeW;        // +W
  state.battery_power = (chargeW != null && dischargeW != null) ? round(chargeW - dischargeW, 1) : null;
} else {
  state.battery_charge = null;
  state.battery_discharge = null;
  state.battery_power = null;
}

// ===== TIMEZONE dayKey (dynamic) =====
function localDayKey(d = new Date()) {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";
  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return `${get("year")}${get("month")}${get("day")}`; // YYYYMMDD
}

const dayKey = localDayKey(new Date());

// ===== DAILY ENERGY (kWh) - Battery charge/discharge today =====
// Intégration simple (trapèze) sur battery_charge/battery_discharge (W)

const kDay = `inv${inv}_batt_dayKey`;
const kTs  = `inv${inv}_batt_lastTs`;
const kChg = `inv${inv}_batt_lastChargeW`;
const kDis = `inv${inv}_batt_lastDischargeW`;
const kChgWh = `inv${inv}_batt_chargeWh_today`;
const kDisWh = `inv${inv}_batt_dischargeWh_today`;

const lastDay = flow.get(kDay);
let lastTs = flow.get(kTs);
let lastChargeW = flow.get(kChg);
let lastDischargeW = flow.get(kDis);

let chargeWh = flow.get(kChgWh);
let dischargeWh = flow.get(kDisWh);

if (!Number.isFinite(chargeWh)) chargeWh = 0;
if (!Number.isFinite(dischargeWh)) dischargeWh = 0;

// Reset si on change de jour
if (lastDay && lastDay !== dayKey) {
  chargeWh = 0;
  dischargeWh = 0;
}

// Puissances actuelles (W) - déjà positives chez toi
const curChargeW = Number.isFinite(state.battery_charge) ? state.battery_charge : 0;
const curDischargeW = Number.isFinite(state.battery_discharge) ? state.battery_discharge : 0;

const nowTs = Date.now();

if (Number.isFinite(lastTs) && Number.isFinite(lastChargeW) && Number.isFinite(lastDischargeW)) {
  const dtMs = nowTs - lastTs;
  // ignore si dt délirant (redémarrage / horloge) : > 10 minutes
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    chargeWh += ((lastChargeW + curChargeW) / 2) * dtH;
    dischargeWh += ((lastDischargeW + curDischargeW) / 2) * dtH;
  }
}

// Stocke contexte
flow.set(kDay, dayKey);
flow.set(kTs, nowTs);
flow.set(kChg, curChargeW);
flow.set(kDis, curDischargeW);
flow.set(kChgWh, chargeWh);
flow.set(kDisWh, dischargeWh);

// Expose dans state en kWh
state.battery_charge_day_kwh = Math.round((chargeWh / 1000) * 100) / 100;
state.battery_discharge_day_kwh = Math.round((dischargeWh / 1000) * 100) / 100;
state._day_key = dayKey; // debug optionnel

// ===== FILTRE ANTI-SPIKE (W) =====
const MAX_W = 15000;

function finiteNumber(x) {
  const nn = Number(x);
  return Number.isFinite(nn) ? nn : null;
}

function clampAbs(x, maxAbs) {
  if (x == null) return null;
  if (Math.abs(x) <= maxAbs) return x;
  return x < 0 ? -maxAbs : maxAbs;
}

// garde dernière valeur OK par inv + key
function sanitizeW(key, { maxAbs = MAX_W, allowNegative = true, forceNonNegative = false } = {}) {
  const v = finiteNumber(state[key]);
  if (v == null) return;

  // force >=0 si demandé
  let vv = v;
  if (forceNonNegative && vv < 0) vv = 0;

  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  // hors limite -> lastOk sinon clamp
  if (Math.abs(vv) > maxAbs) {
    if (lastOk != null && Number.isFinite(lastOk)) {
      state[key] = lastOk;
    } else {
      state[key] = clampAbs(vv, maxAbs);
    }
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, maxAbs });
    return;
  }

  // interdit négatif
  if (!allowNegative && vv < 0) {
    state[key] = (lastOk != null && Number.isFinite(lastOk)) ? lastOk : 0;
    state._spike = state._spike || [];
    state._spike.push({ key, raw: vv, reason: "negative_not_allowed" });
    return;
  }

  // OK -> mémorise
  state[key] = vv;
  flow.set(lastKey, vv);
}

// Champs demandés
sanitizeW("ac_output_active_power", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("grid_power", { maxAbs: MAX_W, allowNegative: true });
sanitizeW("battery_charge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_discharge", { maxAbs: MAX_W, allowNegative: false, forceNonNegative: true });
sanitizeW("battery_power", { maxAbs: MAX_W, allowNegative: true });

// ===== GRID TODAY (kWh) - from grid_power (W) =====
// Intégration trapèze + reset journalier selon timezone config
// On compte uniquement l'import (si grid_power négatif => 0)

const kGDay = `inv${inv}_grid_dayKey`;
const kGTs  = `inv${inv}_grid_lastTs`;
const kGLastW = `inv${inv}_grid_lastW`;
const kGWh = `inv${inv}_grid_Wh_today`;

let gLastDay = flow.get(kGDay);
let gLastTs = flow.get(kGTs);
let gLastW = flow.get(kGLastW);
let gWh = flow.get(kGWh);

if (!Number.isFinite(gWh)) gWh = 0;

// reset jour
if (gLastDay && gLastDay !== dayKey) {
  gWh = 0;
}

// puissance grid actuelle (import only)
const gCurW_raw = Number.isFinite(state.grid_power) ? state.grid_power : 0;
const gCurW = Math.max(0, gCurW_raw);

const gNowTs = Date.now();

if (Number.isFinite(gLastTs) && Number.isFinite(gLastW)) {
  const dtMs = gNowTs - gLastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    gWh += ((gLastW + gCurW) / 2) * dtH;
  }
}

flow.set(kGDay, dayKey);
flow.set(kGTs, gNowTs);
flow.set(kGLastW, gCurW);
flow.set(kGWh, gWh);

// expose en kWh (2 décimales)
state.grid_energy_day_kwh = Math.round((gWh / 1000) * 100) / 100;

context.set("state", state);
msg.inverterNum = inv;
msg.payload = state;
return msg;

// ===============================
// MQTT STATE PUBLISHER (STABLE JSON)
// Garantit une structure toujours identique
// ===============================

if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? 1;
const data = { ...msg.payload };

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const ensure = (obj, key, value = null) => {
    if (obj[key] === undefined) obj[key] = value;
};

// -------------------------------------------------
// 1) STRUCTURE PRINCIPALE
// -------------------------------------------------
ensure(data, "grid_voltage");
ensure(data, "grid_frequency");
ensure(data, "ac_output_voltage");
ensure(data, "ac_output_frequency");
ensure(data, "ac_output_active_power");
ensure(data, "output_load_percent");

ensure(data, "battery_voltage");
ensure(data, "battery_charging_current");
ensure(data, "battery_discharge_current");
ensure(data, "battery_capacity");

ensure(data, "battery_charge");
ensure(data, "battery_discharge");
ensure(data, "battery_power");

ensure(data, "pv_total_power");
ensure(data, "pv1_power");
ensure(data, "pv2_power");

ensure(data, "pv1_input_voltage");
ensure(data, "pv2_input_voltage");
ensure(data, "pv1_input_current");
ensure(data, "pv2_input_current");

ensure(data, "grid_power");
ensure(data, "inverter_heat_sink_temp");

ensure(data, "operation_mode");

// -------------------------------------------------
// 2) ENERGIES (souvent absentes selon timing)
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag) data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");
ensure(data.diag, "fault_state", "unknown");
ensure(data.diag, "fault_details", "unknown");
ensure(data.diag, "warn_state", "unknown");
ensure(data.diag, "warn_details", "unknown");

// -------------------------------------------------
// 4) PARAMS (CRITIQUE POUR SELECT/NUMBER)
// -------------------------------------------------
if (!data.params) data.params = {};
if (!data.params.qpiri) data.params.qpiri = {};
if (!data.params.qdop) data.params.qdop = {};

// valeurs null si pas encore connues (HA ne plantera plus)
const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "output_source_priority");
ensure(qpiri, "charger_source_priority");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

ensure(qpiri, "max_ac_charging_current");
ensure(qpiri, "max_charging_current");
ensure(qpiri, "max_discharging_current");

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");

// -------------------------------------------------
// 5) PUBLISH MQTT
// -------------------------------------------------
return [
    {
        topic: `voltronic/${inv}/state`,
        payload: JSON.stringify(data),
        retain: true
    },
    {
        topic: `voltronic/${inv}/availability`,
        payload: "online",
        retain: true
    }
];

const inv = msg.inverterNum ?? 1;
const key = `inv${inv}_queue`;

let q = flow.get(key);
if (!Array.isArray(q)) q = [];

// msg peut être 1 commande, ou un lot (si tu envoies [msgs])
// Ici, on gère les deux cas proprement.
const toPush = [];

if (Array.isArray(msg)) {
    // rare : si tu envoies direct un tableau de msgs
    toPush.push(...msg);
} else if (Array.isArray(msg.payload) && msg.payload?.[0]?.command) {
    // si jamais ton flow passe un tableau dans payload
    toPush.push(...msg.payload);
} else {
    // msg normal
    toPush.push(msg);
}

// ajoute uniquement si on a une commande
toPush.forEach(m => {
    const cmd = (m.command || m._cmd || m.payload || "").toString().trim().toUpperCase();
    if (!cmd) return;

    q.push({
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        payload: cmd,
        enqueued_ts: Date.now()
    });
});

// limite taille
if (q.length > 200) q = q.slice(-200);

flow.set(key, q);

// déclenche le pump
return { inverterNum: inv, topic: "pump" };

// HA SET -> Voltronic CMD  (1 sortie)
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = (msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);   // ID logique / port RS232 (1..3)
const param = m[2];

// --------------------
// Normalisation payload (fix: guillemets / "200"" / "\"200\"" etc.)
// --------------------
let v = msg.payload;

if (typeof v === "string") {
  v = v.trim();

  // retire guillemets parasites au début/fin
  // ex: '"200"' -> 200 ; '200""' -> 200 ; '"Solar first"' -> Solar first
  v = v.replace(/^"+|"+$/g, "");

  // si c'est encore un JSON string (rare), tente parse
  // ex: "\"200\"" (valeur stringifiée)
  try {
    if (v.startsWith('\\"') || (v.startsWith('"') && v.endsWith('"'))) {
      v = JSON.parse(v);
    }
  } catch (e) {
    // ignore
  }

  if (typeof v === "string") {
    v = v.trim().replace(/^"+|"+$/g, "");
  }
}

// --------------------
// helpers
// --------------------
// robuste: extrait le 1er nombre si string contient des caractères
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = x.trim().replace(/^"+|"+$/g, "");
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");
const fixed1 = (x) => Number(x).toFixed(1);
const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));

// --------------------
// parallel "machine id" (Voltronic parallel ID) != inverterNum (RS232 port)
// --------------------
let machine = flow.get(`inv${inverterNum}_parallel_id`);
if (machine === undefined || machine === null || machine === "") machine = 0;
machine = Number(machine);
if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;

let cmd = null;

// =====================
// SELECTS
// =====================
if (param === "output_source_priority") {
  const map = { UtilitySolarBat: "POP00", SolarUtilityBat: "POP01", SolarBatUtility: "POP02" };
  cmd = map[String(v)] || null;

} else if (param === "charger_source_priority") {
  const map = { "Solar first": "PCP01", "Solar + Utility": "PCP02", "Only solar": "PCP03" };
  cmd = map[String(v)] || null;

} else if (param === "battery_type") {
  const map = {
    AGM: "PBT00",
    Flooded: "PBT01",
    User: "PBT02",
    Pylon: "PBT03",
    Weco: "PBT05",
    Soltaro: "PBT06",
    Lib: "PBT08",
    Lic: "PBT09"
  };
  cmd = map[String(v)] || null;
}

// =====================
// VOLTAGES nn.n
// =====================
else if (param === "battery_recharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCV${fixed1(nv)}`;

} else if (param === "battery_re_discharge_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDV${fixed1(nv)}`;

} else if (param === "battery_under_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDV${fixed1(nv)}`;

} else if (param === "battery_bulk_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PCVV${fixed1(nv)}`;

} else if (param === "battery_float_voltage") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBFT${fixed1(nv)}`;
}

// =====================
// CURRENTS (0..200)
// =====================
else if (param === "max_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MNCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MNCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_ac_charging_current") {
  const nv = toNum(v); if (nv == null) return null;
  // MUCHGC<mnnn> (m = parallel machine id, nnn = current)
  cmd = `MUCHGC${machine}${pad3(clamp(nv, 0, 200))}`;

} else if (param === "max_discharging_current") {
  // PBATMAXDISC<nnn>
  // - 000 = disable (doc)
  // - sinon 001..200 (ton discovery)
  // Si tu utilises "0" = Unsupported côté HA, ne rien envoyer.
  const sv = String(v).trim().replace(/^"+|"+$/g, "");

  // 0 utilisé comme "Unsupported" ? => ignore
  // (si au contraire tu veux "disable", commente ce bloc)
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  // Ici: 1..200
  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
}

// =====================
// QDOP thresholds %
// =====================
else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
}

if (!cmd) return null;

// --------------------
// message builder
// --------------------
const mk = (c) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true
});

// 1) SET message (priority)
const setMsg = mk(cmd);
setMsg._burst = false;

// 2) Refresh burst after SET
const refresh = ["QPIRI", "QDI", "QFLAG", "QDOP", "QMOD", "QPIGS"];
// optional if supported: refresh.splice(refresh.indexOf("QPIGS")+1, 0, "QPIGS2");

const out = [setMsg, ...refresh.map(mk)];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${out.length - 1}`
});

// 1 output => array of messages in output 1
return [out];

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

msg.inverterNum = 2;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

msg.inverterNum = 1;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let inFlight = flow.get(inFlightKey);

// Si une commande est déjà en attente de réponse, on n’en envoie pas une autre
if (inFlight && (Date.now() - (inFlight.ts || 0)) < 3000) {
  return null;
}

let q = flow.get(qKey);
if (!Array.isArray(q) || q.length === 0) return null;

// Prend la prochaine commande
const next = q.shift();
flow.set(qKey, q);

// Marque comme en vol
flow.set(inFlightKey, { cmd: next.command, ts: Date.now() });

// Envoie au construire commande
return next;

// Transport Select (2 outputs): [SERIAL, TCP]
const inv = Number(msg.inverterNum || 1);

let t =
    (msg.transport || "").toString().toLowerCase().trim() ||
    (flow.get(`inv${inv}_transport`) || "").toString().toLowerCase().trim() ||
    (env.get(`INV${inv}_TRANSPORT`) || "").toString().toLowerCase().trim() ||
    "serial";

if (t !== "tcp" && t !== "serial") t = "serial";
msg.transport = t;

msg.tcpHost =
    msg.tcpHost ||
    flow.get(`inv${inv}_tcp_host`) ||
    env.get(`INV${inv}_TCP_HOST`) ||
    "192.168.1.40";

msg.tcpPort =
    Number(
        msg.tcpPort ||
        flow.get(`inv${inv}_tcp_port`) ||
        env.get(`INV${inv}_TCP_PORT`) ||
        8899
    ) || 8899;

if (t === "tcp") return [null, msg];
return [msg, null];

// TCP TX gate: ne laisse passer que si Transport Select a choisi TCP
if ((msg.transport || "").toString().toLowerCase() !== "tcp") return null;

// sécurité: on envoie uniquement un Buffer (commande construite)
if (!Buffer.isBuffer(msg.payload)) return null;

return msg;

msg.inverterNum = 3;
if (!Buffer.isBuffer(msg.payload)) return null;
return msg;

// =======================
// MQTT DISCOVERY - VOLTRONIC (SAFE TEMPLATES)
// VERSION PAR ONDULEUR
// Compatible serial + gateway/tcp
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
