// =======================
// Config inverter depuis parse options
// =======================
const invCfgAll = global.get("config.invCfg") || {};
const enabledInvs = Array.isArray(global.get("config.invertersList"))
  ? global.get("config.invertersList").map(Number).filter(n => [1, 2, 3].includes(n))
  : [];

const cfg = invCfgAll[inv] || {};
const enabled = enabledInvs.includes(inv);

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV
});

const lastSigKey = `inv${inv}_discovery_signature`;
const topicsKey = `inv${inv}_discovery_topics`;
const lastSig = flow.get(lastSigKey);
const changed = (lastSig !== signature);

// -----------------------
// Jinja helpers (SAFE)
// -----------------------
const jNum = (path, fallback = 0) => `{{ ${path} | default(${fallback}, true) }}`;
const jStr = (path, fallback = "unknown") => `{{ ${path} | default('${fallback}', true) }}`;
const jDeep = (expr) => `{{ ${expr} }}`;

// Common deep roots
const QPIRI = `value_json.get('params', {}).get('qpiri', {})`;
const QDOP  = `value_json.get('params', {}).get('qdop', {})`;

// Topics inverter
const base = `${BASE_TOPIC}/${inv}`;
const state_topic = `${base}/state`;
const availability_topic = `${base}/availability`;
const set_base = `${base}/set`;

const device = {
  identifiers: [`voltronic_inv_${inv}`],
  name: `Voltronic Inverter ${inv}`,
  manufacturer: "Voltronic",
  model: "Axpert/Voltronic",
};

// mémorise les topics config publiés pour pouvoir les supprimer plus tard
const publishedTopics = [];

function sensorCfg(objectId, name, unit, device_class, state_class, valueTpl, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/sensor/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    device,
    ...extra,
  };

  if (unit) payload.unit_of_measurement = unit;
  if (device_class) payload.device_class = device_class;
  if (state_class) payload.state_class = state_class;

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

